-- Extend category constraint to include football_*
alter table public.exercises drop constraint if exists exercises_category_check;
alter table public.exercises add constraint exercises_category_check
  check (category in (
    'warmup', 'functional', 'team', 'balance',
    'flexibility', 'cardio', 'mobility', 'cooldown',
    'green', 'pair',
    'football_warmup', 'football_drill', 'football_trick', 'football_game'
  ));

insert into public.exercises (
  slug, category, difficulty,
  name, description,
  video_url, equipment, duration_minutes,
  min_age, max_age,
  why_matters, key_focus, pro_tip
) values
  (
    'football-jogging-with-ball',
    'football_warmup',
    'low',
    '{"en":"Jogging with Ball","it":"Corsa con Pallone","pl":"Bieganie z Piłką","uk":"Біг із М''ячем"}'::jsonb,
    '{"en":"Jogging with the ball helps players get comfortable with ball control while moving at a low intensity. 1. Start with players standing still, each with a ball.\n2. Instruct them to begin jogging slowly while keeping the ball close to their feet.\n3. Encourage players to use different parts of their feet to control the ball.","pl":"Bieganie z piłką pomaga zawodnikom przyzwyczaić się do kontroli piłki podczas poruszania się z niską intensywnością. 1. Zacznij z zawodnikami stojącymi w miejscu, każdy z piłką.\n2. Nakazuj im zacząć biegać wolno, trzymając piłkę blisko stóp.\n3. Zachęcaj zawodników do używania różnych części stóp do kontroli piłki.","it":"La corsa con il pallone aiuta i giocatori a sentirsi a loro agio con il controllo del pallone mentre si muovono a bassa intensità. 1. Inizia con i giocatori fermi, ciascuno con un pallone.\n2. Istruiscili a iniziare a correre lentamente mentre tengono il pallone vicino ai piedi.\n3. Incoraggia i giocatori a usare diverse parti dei piedi per controllare il pallone.","uk":"Біг із м''ячем допомагає гравцям відчути комфорт із контролем м''яча під час руху на низькій інтенсивності. 1. Почніть із гравцями, які стоять на місці, кожен із м''ячем.\n2. Наказуйте їм почати бігти повільно, тримаючи м''яч біля ніг.\n3. Заохочуйте гравців використовувати різні частини ніг для контролю м''яча."}'::jsonb,
    'https://www.youtube.com/watch?v=qFTjyXNXSBE',
    '{"ball"}'::text[],
    4,
    12,
    99,
    '{"en":"This exercise matters because it helps players develop basic ball control skills in a low-pressure environment. Famous players like Lionel Messi and Cristiano Ronaldo have emphasized the importance of ball control in their training.","it":"Questo esercizio è importante perché aiuta i giocatori a sviluppare abilità di base nel controllo del pallone in un ambiente a bassa pressione. Giocatori famosi come Lionel Messi e Cristiano Ronaldo hanno sottolineato l''importanza del controllo del pallone nel loro allenamento.","pl":"Ten ćwiczenie jest ważne, ponieważ pomaga zawodnikom rozwinąć podstawowe umiejętności kontroli piłki w środowisku o niskim ciśnieniu. Znani zawodnicy, tacy jak Lionel Messi i Cristiano Ronaldo, podkreślali znaczenie kontroli piłki w swoim treningu.","uk":"Це вправу важливе, тому що воно допомагає гравцям розвивати базові навички контролю м''яча в середовищі з низьким тиском. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, підкреслювали важливість контролю м''яча у своєму тренуванні."}'::jsonb,
    '{"en":["Keep the ball close to feet","Use different parts of the feet","Maintain a slow and steady pace"],"it":["Tieni il pallone vicino ai piedi","Usa diverse parti dei piedi","Mantieni un ritmo lento e costante"],"pl":["Trzymaj piłkę blisko stóp","Używaj różnych części stóp","Utrzymuj wolne i stałe tempo"],"uk":["Тримай м''яч біля ніг","Використовуй різні частини ніг","Підтримуй повільне та стале темпо"]}'::jsonb,
    '{"en":"Encourage players to keep their heads up and be aware of their surroundings while jogging with the ball.","it":"Incoraggia i giocatori a tenere la testa alta e a essere consapevoli dell''ambiente circostante mentre corrono con il pallone.","pl":"Zachęcaj zawodników do trzymania głowy do góry i bycia świadomym otoczenia podczas biegu z piłką.","uk":"Заохочуйте гравців тримати голову високо та бути обізнаними із своїм оточенням під час бігу із м''ячем."}'::jsonb
  ),
  (
    'fifa-11plus-running-program',
    'football_warmup',
    'low',
    '{"en":"FIFA 11+ Running Program","it":"Programma di corsa FIFA 11+","pl":"Program do rozgrzewki FIFA 11+","uk":"Програма бігу FIFA 11+"}'::jsonb,
    '{"en":"A dynamic warm-up program to prepare players for football training and matches. 1. Jog in place, then move to leg swings, arm circles, and hip rotations. 2. Perform walking lunges and leg raises. 3. Move to high knees, butt kicks, and carioca drills.","pl":"Dynamiczny program rozgrzewki przygotowujący zawodników do treningów i meczów piłki nożnej. 1. Bieganie w miejscu, następnie wymachy nóg, krążenia ramion i rotacje bioder. 2. Wykonywanie wykroków i unoszeń nóg. 3. Przejście do wysokich kolan, kopnięć połykowych i ćwiczeń carioca.","it":"Un programma di riscaldamento dinamico per preparare i giocatori agli allenamenti e alle partite di calcio. 1. Trottare sul posto, poi passare a oscillazioni delle gambe, cerchi con le braccia e rotazioni dell''anca. 2. Eseguire affondi camminati e sollevamenti delle gambe. 3. Passare a ginocchia alte, calci ai glutei e esercizi carioca.","uk":"Динамічна програма розминки для підготовки гравців до тренувань і матчів з футболу. 1. Біг на місці, потім махи ногами, кола руками і обертання стегнами. 2. Виконання випади і підйоми ніг. 3. Перехід до високих колін, ударів по сідницях і вправ каріока."}'::jsonb,
    'https://www.youtube.com/watch?v=oCaarADKWRk',
    '{}'::text[],
    5,
    12,
    99,
    '{"en":"This program helps prevent injuries and improves performance by preparing players'' muscles and joints for football activities. Many professional players, including Cristiano Ronaldo, use similar warm-up routines.","it":"Questo programma aiuta a prevenire gli infortuni e migliora le prestazioni preparando i muscoli e le articolazioni dei giocatori per le attività di calcio. Molti giocatori professionisti, tra cui Cristiano Ronaldo, utilizzano routine di riscaldamento simili.","pl":"Ten program pomaga zapobiegać kontuzjom i poprawia wyniki poprzez przygotowanie mięśni i stawów zawodników do aktywności piłkarskich. Wielu profesjonalnych zawodników, w tym Cristiano Ronaldo, stosuje podobne rozgrzewki.","uk":"Ця програма допомагає запобігати травмам і поліпшує результати шляхом підготовки м''язів і суглобів гравців до футбольної діяльності. Багато професійних гравців, включаючи Кріштіану Роналду, використовують подібні процедури розминки."}'::jsonb,
    '{"en":["Dynamic movement","Muscle activation","Injury prevention"],"it":["Movimento dinamico","Attivazione muscolare","Prevenzione infortuni"],"pl":["Ruch dynamiczny","Aktywacja mięśni","Zapobieganie kontuzjom"],"uk":["Динамічний рух","Активація м''язів","Запобігання травмам"]}'::jsonb,
    '{"en":"Make sure to listen to your body and adjust the intensity and duration of the warm-up based on your individual needs.","it":"Assicurati di ascoltare il tuo corpo e di regolare l''intensità e la durata del riscaldamento in base alle tue esigenze individuali.","pl":"Upewnij się, że słuchasz swojego ciała i dostosuj intensywność oraz czas trwania rozgrzewki do Twoich indywidualnych potrzeb.","uk":"Впевніться, що ви слухаєте своє тіло і регулюєте інтенсивність та тривалість розминки відповідно до ваших індивідуальних потреб."}'::jsonb
  ),
  (
    'dynamic-leg-swings-ball',
    'football_warmup',
    'low',
    '{"en":"Dynamic Leg Swings with Ball","it":"Oscillazioni Dinamiche delle Gambe con Pallone","pl":"Dynamiczne Wahania Nóg z Piłką","uk":"Динамічні Махи Ног з М''ячем"}'::jsonb,
    '{"en":"This exercise involves swinging your legs in different directions while controlling the ball to loosen up your muscles and improve coordination. 1. Stand with the ball at your feet. 2. Swing one leg forward and backward, then switch to the other leg. 3. Move your legs in a circular motion, first clockwise and then counterclockwise. 4. Keep your knees slightly bent and your eyes on the ball.","pl":"Ten ćwiczenie polega na wymachiwaniu nogami w różnych kierunkach przy kontroli piłki, aby rozluźnić mięśnie i poprawić koordynację. 1. Stań z piłką u nogi. 2. Wymachuj jedną nogą do przodu i do tyłu, następnie przejdź do drugiej nogi. 3. Poruszaj nogami w ruchu okrężnym, najpierw zgodnie z ruchem wskazówek zegara, a następnie przeciwnie. 4. Trzymaj kolana lekko ugięte, a oczy na piłce.","it":"Questo esercizio consiste nell''oscillare le gambe in diverse direzioni controllando il pallone per sciogliere i muscoli e migliorare la coordinazione. 1. Stai in piedi con il pallone ai tuoi piedi. 2. Oscillare una gamba avanti e indietro, poi passare all''altra gamba. 3. Muovere le gambe in un movimento circolare, prima in senso orario e poi in senso antiorario. 4. Tenere le ginocchia leggermente piegate e gli occhi sul pallone.","uk":"Це вправа полягає у маханні ногами у різних напрямках із контролем м''яча, щоб розігріти м''язи та покращити координацію. 1. Станьте з м''ячем біля ніг. 2. Махайте однією ногою вперед і назад, потім переходьте до іншої ноги. 3. Рухайте ногами по колу, спочатку за годинниковою стрілкою, а потім проти неї. 4. Тримайте коліна трохи зігнутими, а очі на м''ячі."}'::jsonb,
    'https://www.youtube.com/watch?v=Vbsgi0gOPHs',
    '{"ball"}'::text[],
    3,
    12,
    99,
    '{"en":"This exercise helps improve flexibility, coordination, and balance. Famous players like Lionel Messi and Cristiano Ronaldo incorporate dynamic movements into their warm-ups to prepare for matches.","it":"Questo esercizio aiuta a migliorare la flessibilità, la coordinazione e l''equilibrio. Giocatori famosi come Lionel Messi e Cristiano Ronaldo incorporano movimenti dinamici nei loro riscaldamenti per prepararsi alle partite.","pl":"To ćwiczenie pomaga poprawić elastyczność, koordynację i równowagę. Znani piłkarze tacy jak Lionel Messi i Cristiano Ronaldo włączają dynamiczne ruchy do swoich rozgrzewek, aby przygotować się do meczów.","uk":"Це вправа допомагає покращити гнучкість, координацію та рівновагу. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, включають динамічні рухи у свої розминки, щоб підготуватися до матчів."}'::jsonb,
    '{"en":["Ball control","Leg movement","Balance"],"it":["Controllo del pallone","Movimento delle gambe","Equilibrio"],"pl":["Kontrola piłki","Ruch nogami","Równowaga"],"uk":["Контроль м''яча","Рух ногами","Рівновага"]}'::jsonb,
    '{"en":"Keep your movements smooth and controlled to maximize the effectiveness of the exercise.","it":"Mantieni i movimenti fluidi e controllati per massimizzare l''efficacia dell''esercizio.","pl":"Trzymaj płynne i kontrolowane ruchy, aby maksymalnie wykorzystać skuteczność ćwiczenia.","uk":"Тримайте рухи плавними та контрольованими, щоб максимально підвищити ефективність вправи."}'::jsonb
  ),
  (
    'ladder-agility-warmup',
    'football_warmup',
    'mid',
    '{"en":"Ladder Agility Warmup","it":"Riscaldamento con Scala di Agilità","pl":"Rozgrzewka z drabinką","uk":"Розминка з драбинкою"}'::jsonb,
    '{"en":"Improves agility and speed with ladder drills. 1. Set up a ladder on the ground. 2. Perform different footwork patterns through the ladder, such as high knees, carioca drills, and lateral shuffles. 3. Focus on quick changes of direction and speed. 4. Repeat for 4 minutes.","pl":"Poprawia zwinność i szybkość dzięki ćwiczeniom z drabinką. 1. Ustaw drabinkę na ziemi. 2. Wykonuj różne wzory pracy nóg przez drabinkę, takie jak wysokie kolana, ćwiczenia carioca i przesunięcia boczne. 3. Skoncentruj się na szybkich zmianach kierunku i prędkości. 4. Powtórz przez 4 minuty.","it":"Migliora agilità e velocità con esercizi sulla scala. 1. Posiziona una scala a terra. 2. Esegui diversi schemi di lavoro con i piedi attraverso la scala, come ginocchia alte, esercizi carioca e scivolamenti laterali. 3. Concentrati su rapidi cambiamenti di direzione e velocità. 4. Ripeti per 4 minuti.","uk":"Покращує спритність та швидкість за допомогою вправ з драбинкою. 1. Встановіть драбинку на землі. 2. Виконуйте різні схеми роботи ногами через драбинку, такі як високі коліна, вправи каріока та бічні переміщення. 3. Зосередьтесь на швидких змінах напрямку та швидкості. 4. Повторіть протягом 4 хвилин."}'::jsonb,
    'https://www.youtube.com/watch?v=Bdr0vKBsdT0',
    '{}'::text[],
    4,
    12,
    99,
    '{"en":"This exercise improves agility, speed, and reaction time. Famous players like Cristiano Ronaldo and Lionel Messi use ladder drills to enhance their performance.","it":"Questo esercizio migliora agilità, velocità e tempo di reazione. Giocatori famosi come Cristiano Ronaldo e Lionel Messi utilizzano esercizi con la scala per migliorare le loro prestazioni.","pl":"To ćwiczenie poprawia zwinność, szybkość i czas reakcji. Znani piłkarze tacy jak Cristiano Ronaldo i Lionel Messi używają ćwiczeń z drabinką, aby poprawić swoją wydajność.","uk":"Це вправа покращує спритність, швидкість та час реакції. Відомі гравці, такі як Кріштіану Роналду та Ліонель Мессі, використовують вправи з драбинкою, щоб покращити свою продуктивність."}'::jsonb,
    '{"en":["Quick changes of direction","Speed and agility","Footwork technique"],"it":["Cambiamenti rapidi di direzione","Velocità e agilità","Tecnica di lavoro con i piedi"],"pl":["Szybkie zmiany kierunku","Szybkość i zwinność","Technika pracy nóg"],"uk":["Швидкі зміни напрямку","Швидкість та спритність","Техніка роботи ногами"]}'::jsonb,
    '{"en":"Focus on explosive movements and proper footwork technique to get the most out of this exercise.","it":"Concentrati su movimenti esplosivi e una corretta tecnica di lavoro con i piedi per ottenere il massimo da questo esercizio.","pl":"Skoncentruj się na wybuchowych ruchach i właściwej technice pracy nóg, aby uzyskać jak najwięcej z tego ćwiczenia.","uk":"Зосередьтесь на вибухових рухах та правильній техніці роботи ногами, щоб отримати максимум від цієї вправи."}'::jsonb
  ),
  (
    'high-knees-with-ball-pickup',
    'football_warmup',
    'mid',
    '{"en":"High Knees with Ball Pickup","pl":"Bieg z wysokimi kolanami i podaniem piłki","it":"Corsa con ginocchia alti e recupero palla","uk":"Біг з високими колінами та підбором м''яча"}'::jsonb,
    '{"en":"Run with high knees while picking up a ball, improving coordination and agility. 1. Start with a ball on the ground. 2. Begin running with high knees, lifting your legs to hip level. 3. As you run, pick up the ball and hold it for a few seconds. 4. Continue running and repeat the ball pickup process several times.","pl":"Bieg z wysokimi kolanami podczas podnoszenia piłki, poprawiający koordynację i zwinność. 1. Rozpocznij z piłką na ziemi. 2. Biegnij z wysokimi kolanami, unosząc nogi do poziomu bioder. 3. Podczas biegu podnieś piłkę i trzymaj ją przez kilka sekund. 4. Kontynuuj bieg i powtarzaj proces podnoszenia piłki kilka razy.","it":"Corsa con ginocchia alti mentre si recupera una palla, migliorando la coordinazione e l''agilità. 1. Inizia con una palla a terra. 2. Inizia a correre con ginocchia alti, sollevando le gambe a livello dell''anca. 3. Mentre corri, recupera la palla e tienila per alcuni secondi. 4. Continua a correre e ripeti il processo di recupero della palla più volte.","uk":"Біг з високими колінами під час підбору м''яча, що покращує координацію та спритність. 1. Почніть з м''ячем на землі. 2. Біжіть з високими колінами, піднімаючи ноги до рівня стегна. 3. Під час бігу підберіть м''яч і тримайте його кілька секунд. 4. Продовжуйте біг і повторіть процес підбору м''яча кілька разів."}'::jsonb,
    'https://www.youtube.com/watch?v=7QwGyOQfL_E',
    '{"ball"}'::text[],
    3,
    12,
    99,
    '{"en":"This exercise improves coordination, agility, and ball control. Famous players like Lionel Messi and Cristiano Ronaldo use similar drills to enhance their skills.","pl":"Ten ćwiczenie poprawia koordynację, zwinność i kontrolę nad piłką. Znani piłkarze tacy jak Lionel Messi i Cristiano Ronaldo korzystają z podobnych ćwiczeń, aby poprawić swoje umiejętności.","it":"Questo esercizio migliora la coordinazione, l''agilità e il controllo della palla. Giocatori famosi come Lionel Messi e Cristiano Ronaldo utilizzano esercizi simili per migliorare le loro abilità.","uk":"Це вправ допомагає покращити координацію, спритність та контроль над м''ячем. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, використовують подібні вправи, щоб покращити свої навички."}'::jsonb,
    '{"en":["High knee lift","Ball pickup","Coordination","Agility"],"pl":["Wysokie unoszenie kolan","Podnoszenie piłki","Koordynacja","Zwinność"],"it":["Alzata ginocchia","Recupero palla","Coordinazione","Agilità"],"uk":["Високе піднімання колін","Підбір м''яча","Координація","Спритність"]}'::jsonb,
    '{"en":"Keep your core engaged and focus on quick ball pickups to maximize the exercise''s effectiveness.","pl":"Utrzymuj napięty tułów i skup się na szybkim podnoszeniu piłki, aby maksymalnie wykorzystać skuteczność ćwiczenia.","it":"Mantieni il core attivo e concentrati su rapidi recuperi della palla per massimizzare l''efficacia dell''esercizio.","uk":"Тримайте свій корпус напруженим і зосередьтеся на швидкому підборі м''яча, щоб максимально підвищити ефективність вправи."}'::jsonb
  ),
  (
    'side-shuffle-and-pass',
    'football_warmup',
    'low',
    '{"en":"Side Shuffle and Pass","it":"Sfondo Laterale e Passaggio","pl":"Przesunięcie Boczne i Podanie","uk":"Бічне Переміщення і Паса"}'::jsonb,
    '{"en":"A warm-up exercise that combines lateral movement with passing. 1. Players start in a line facing the coach or a teammate. 2. Shuffle sideways to one side while keeping eyes on the ball. 3. Receive a pass from the coach or teammate. 4. Pass the ball back immediately.","pl":"Ćwiczenie rozgrzewające łączące przesunięcie boczne z podaniem. 1. Zawodnicy ustawią się w linii twarzą do trenera lub partnera. 2. Przesuwają się bokiem w jedną stronę, trzymając wzrok na piłce. 3. Otrzymują podanie od trenera lub partnera. 4. Natychmiast oddają piłkę z powrotem.","it":"Un esercizio di riscaldamento che combina movimento laterale e passaggio. 1. I giocatori iniziano in linea di fronte all''allenatore o a un compagno. 2. Si spostano lateralmente da un lato mentre tengono gli occhi sulla palla. 3. Ricevono un passaggio dall''allenatore o dal compagno. 4. Passano la palla indietro immediatamente.","uk":"Вправа для розминки, що поєднує бічне переміщення і пас. 1. Гравці вишиковуються в лінію обличчям до тренера або партнера. 2. Переміщуються вбік на один бік, стежачи за м''ячем. 3. Отримують пас від тренера або партнера. 4. Відразу віддають м''яч назад."}'::jsonb,
    'https://www.youtube.com/watch?v=AnP_MJq3hMo',
    '{"ball"}'::text[],
    4,
    12,
    99,
    '{"en":"This exercise helps improve agility, reaction time, and passing accuracy. Famous players like Lionel Messi and Cristiano Ronaldo emphasize the importance of agility in their training.","it":"Questo esercizio aiuta a migliorare l''agilità, il tempo di reazione e la precisione di passaggio. Giocatori famosi come Lionel Messi e Cristiano Ronaldo sottolineano l''importanza dell''agilità nel loro allenamento.","pl":"To ćwiczenie pomaga poprawić zwinność, czas reakcji i dokładność podań. Znani piłkarze tacy jak Lionel Messi i Cristiano Ronaldo podkreślają znaczenie zwinności w swoim treningu.","uk":"Ця вправа допомагає поліпшити спритність, час реакції та точність пасів. Відомі гравці, такі як Ліонель Мессі і Кріштіану Роналду, підкреслюють важливість спритності у своєму тренуванні."}'::jsonb,
    '{"en":["Lateral movement","Ball control","Quick passing"],"it":["Movimento laterale","Controllo della palla","Passaggio rapido"],"pl":["Przesunięcie boczne","Kontrola piłki","Szybkie podanie"],"uk":["Бічне переміщення","Контроль м''яча","Швидкий пас"]}'::jsonb,
    '{"en":"Keep your eyes up and focused on the ball while shuffling.","it":"Tieni gli occhi in alto e concentrati sulla palla mentre ti sposti.","pl":"Trzymaj wzrok w górze i skup się na piłce podczas przesunięcia.","uk":"Тримайте очі вгорі і зосередьтесь на м''ячі під час переміщення."}'::jsonb
  ),
  (
    'open-close-the-gate',
    'football_warmup',
    'low',
    '{"en":"Open Close Gate","it":"Apri Chiudi Porta","pl":"Otwórz Zamknij Bramę","uk":"Відкрий Закрий Ворота"}'::jsonb,
    '{"en":"A dynamic warm-up exercise to loosen up the legs and hips. 1. Stand with your feet shoulder-width apart. 2. Move one foot to the side, keeping the other foot planted. 3. Quickly return to the starting position and repeat with the other foot.","pl":"Dynamiczne ćwiczenie rozgrzewające nogi i biodra. 1. Stań ze stopami rozstawionymi na szerokość barków. 2. Przesuń jedną stopę w bok, trzymając drugą stopę na miejscu. 3. Szybko wróć do pozycji wyjściowej i powtórz z drugą stopą.","it":"Esercizio di riscaldamento dinamico per sciogliere le gambe e i fianchi. 1. Stai con i piedi larghi quanto le spalle. 2. Sposta un piede lateralmente, tenendo l''altro piede fermo. 3. Ritorna rapidamente alla posizione iniziale e ripeti con l''altro piede.","uk":"Динамічна вправа для розминки ніг та стегон. 1. Станте з ногами на ширині плечей. 2. Перемістіть одну ногу вбік, тримаючи іншу ногу на місці. 3. Швидко поверніться у вихідне положення та повторіть іншою ногою."}'::jsonb,
    'https://www.youtube.com/watch?v=DDqgGYzWVI4',
    '{}'::text[],
    3,
    12,
    99,
    '{"en":"This exercise helps improve flexibility and coordination. Famous players like Cristiano Ronaldo and Lionel Messi use dynamic warm-ups to prepare for matches.","it":"Questo esercizio aiuta a migliorare la flessibilità e la coordinazione. Giocatori famosi come Cristiano Ronaldo e Lionel Messi utilizzano riscaldamenti dinamici per prepararsi alle partite.","pl":"To ćwiczenie pomaga poprawić elastyczność i koordynację. Znani piłkarze tacy jak Cristiano Ronaldo i Lionel Messi używają rozgrzewki dynamicznej przed meczami.","uk":"Ця вправа допомагає покращити гнучкість та координацію. Відомі гравці такі як Крістіано Роналду та Ліонель Мессі використовують динамічну розминку для підготовки до матчів."}'::jsonb,
    '{"en":["Quick movements","Leg flexibility","Hip rotation"],"it":["Movimenti rapidi","Flessibilità delle gambe","Rotazione dei fianchi"],"pl":["Szybkie ruchy","Elastyczność nóg","Rotacja bioder"],"uk":["Швидкі рухи","Гнучкість ніг","Обертання стегон"]}'::jsonb,
    '{"en":"Keep your knees slightly bent to maintain balance and generate power.","it":"Tieni le ginocchia leggermente piegate per mantenere l''equilibrio e generare potenza.","pl":"Trzymaj kolana lekko zgięte, aby utrzymać równowagę i generować siłę.","uk":"Тримайте коліна трохи зігнутими, щоб зберегти рівновагу та генерувати силу."}'::jsonb
  ),
  (
    'progressive-sprints',
    'football_warmup',
    'mid',
    '{"en":"Progressive Sprints","it":"Sprint Progressivi","pl":"Biegi Progresywne","uk":"Прогресивні Спринти"}'::jsonb,
    '{"en":"A dynamic warm-up exercise that involves sprinting with increasing intensity to prepare players for the game. 1. Start with a light jog to get the players moving. 2. Gradually increase the intensity to a sprint, focusing on proper running technique. 3. After 20-30 seconds of sprinting, walk or jog back to recover. 4. Repeat for 5 minutes, increasing the sprint intensity each time.","pl":"Ćwiczenie rozgrzewające, które polega na bieganiu ze stopniowo rosnącą intensywnością, aby przygotować zawodników do meczu. 1. Rozpocznij od lekkiego biegu, aby zawodnicy mogli się poruszać. 2. Stopniowo zwiększaj intensywność do biegu sprintowego, skupiając się na właściwej technice biegu. 3. Po 20-30 sekundach biegu, wróć do chodu lub lekkiego biegu, aby się zregenerować. 4. Powtórz przez 5 minut, zwiększając intensywność biegu za każdym razem.","it":"Esercizio di riscaldamento dinamico che consiste nel correre a velocità crescente per preparare i giocatori alla partita. 1. Inizia con una corsa leggera per far muovere i giocatori. 2. Aumenta gradualmente l''intensità fino a un ritmo di corsa, concentrati sulla tecnica di corsa corretta. 3. Dopo 20-30 secondi di corsa, cammina o corri indietro per recuperare. 4. Ripeti per 5 minuti, aumentando l''intensità della corsa ogni volta.","uk":"Динамічна вправа для розминки, яка полягає в бігу зі зростаючою інтенсивністю для підготовки гравців до гри. 1. Почніть з легкого бігу, щоб гравці почали рухатися. 2. Поступово збільшуйте інтенсивність до спринту, зосереджуючись на правильній техніці бігу. 3. Через 20-30 секунд бігу, поверніться до ходьби або легкого бігу, щоб відновитися. 4. Повторіть протягом 5 хвилин, збільшуючи інтенсивність спринту кожного разу."}'::jsonb,
    'https://www.youtube.com/watch?v=Ji_kSAB9Bj0',
    '{}'::text[],
    5,
    12,
    99,
    '{"en":"This exercise is essential for preparing players for the high-intensity demands of a football game. Progressive sprints help improve cardiovascular endurance, speed, and agility. Many professional players, such as Cristiano Ronaldo and Lionel Messi, incorporate sprint training into their fitness regimens.","it":"Questo esercizio è fondamentale per preparare i giocatori alle elevate esigenze di intensità di una partita di calcio. I sprint progressivi aiutano a migliorare la resistenza cardiovascolare, la velocità e l''agilità. Molti giocatori professionisti, come Cristiano Ronaldo e Lionel Messi, includono l''allenamento con sprint nella loro routine di fitness.","pl":"To ćwiczenie jest niezbędne do przygotowania zawodników do wysokich wymagań intensywności w meczu piłkarskim. Biegi progresywne pomagają poprawić wytrzymałość kardiowaskularną, szybkość i zwinność. Wielu profesjonalnych zawodników, takich jak Cristiano Ronaldo i Lionel Messi, włącza trening sprinterski do swojego programu fitness.","uk":"Ця вправа є необхідною для підготовки гравців до високих вимог інтенсивності у футбольному матчі. Прогресивні спринти допомагають поліпшити серцево-судинну витривалість, швидкість і спритність. Багато професійних гравців, такі як Крістіано Роналду і Ліонель Мессі, включають спринтерський тренінг до свого фітнес-програми."}'::jsonb,
    '{"en":["Proper running technique","Increasing intensity","Recovery time"],"it":["Tecnica di corsa corretta","Aumento dell''intensità","Tempo di recupero"],"pl":["Właściwa technika biegu","Zwiększanie intensywności","Czas regeneracji"],"uk":["Правильна техніка бігу","Збільшення інтенсивності","Час відновлення"]}'::jsonb,
    '{"en":"Make sure to focus on quick recovery times to maximize the effectiveness of the exercise.","it":"Assicurati di concentrarti sui tempi di recupero rapidi per massimizzare l''efficacia dell''esercizio.","pl":"Upewnij się, że skupiasz się na szybkim czasie regeneracji, aby maksymalnie wykorzystać skuteczność ćwiczenia.","uk":"Переконайтеся, що зосереджуєтеся на швидкому часі відновлення, щоб максимально підвищити ефективність вправи."}'::jsonb
  ),
  (
    'wall-pass-rebound',
    'football_drill',
    'low',
    '{"en":"Wall Pass Rebound","it":"Rimbalzo di Passaggio","pl":"Podanie ze ścianą i odbiciem","uk":"Трик зі стіною та відскоком"}'::jsonb,
    '{"en":"Players practice passing with a teammate and then making a run to receive a rebound pass. 1. Divide players into pairs.\n2. One player acts as the passer, the other as the receiver.\n3. The passer plays the ball against a wall or solid surface.\n4. The receiver makes a run to meet the rebounding ball.","pl":"Zawodnicy ćwiczą podanie z partnerem, a następnie biegną, aby otrzymać podanie z odbiciem. 1. Podziel zawodników na pary.\n2. Jeden zawodnik jest podającym, drugi odbiorcą.\n3. Podający uderza piłkę w ścianę lub inną powierzchnię.\n4. Odbiorca biegnie, aby odebrać piłkę po odbiciu.","it":"Giocatori praticano il passaggio con un compagno e poi fanno una corsa per ricevere un passaggio di rimbalzo. 1. Dividere i giocatori in coppie.\n2. Un giocatore fa il passatore, l''altro il ricevitore.\n3. Il passatore gioca la palla contro un muro o una superficie solida.\n4. Il ricevitore corre incontro alla palla in ricorsa.","uk":"Гравці тренують передачу м''яча з партнером і потім біжать, щоб отримати передачу з відскоком. 1. Розділіть гравців на пари.\n2. Один гравець є гравцем, що передає м''яч, інший - гравцем, що приймає.\n3. Гравець, що передає, б''є м''яч об стіну або іншу поверхню.\n4. Гравець, що приймає, біжить назустріч м''ячу, що відскакує."}'::jsonb,
    'https://www.youtube.com/watch?v=K9zMUbHBxSE',
    '{"ball"}'::text[],
    8,
    12,
    99,
    '{"en":"This exercise helps improve passing accuracy and reaction time. Famous players like Lionel Messi and Cristiano Ronaldo use similar drills to enhance their ball control.","it":"Questo esercizio aiuta a migliorare la precisione di passaggio e il tempo di reazione. Giocatori famosi come Lionel Messi e Cristiano Ronaldo utilizzano esercizi simili per migliorare il controllo della palla.","pl":"To ćwiczenie pomaga poprawić dokładność podań i czas reakcji. Zawodnicy tacy jak Lionel Messi i Cristiano Ronaldo korzystają z podobnych ćwiczeń, aby poprawić kontrolę nad piłką.","uk":"Це вправа допомагає покращити точність передач і час реакції. Такі гравці, як Ліонель Мессі та Кріштіану Роналду, використовують подібні вправи для покращення контролю над м''ячем."}'::jsonb,
    '{"en":["Passing accuracy","Reaction time","Ball control"],"it":["Precisione di passaggio","Tempo di reazione","Controllo della palla"],"pl":["Dokładność podań","Czas reakcji","Kontrola piłki"],"uk":["Точність передач","Час реакції","Контроль над м''ячем"]}'::jsonb,
    '{"en":"Communicate with your teammate to anticipate the rebound and adjust your run accordingly.","it":"Comunica con il tuo compagno per anticipare il rimbalzo e aggiusta la tua corsa di conseguenza.","pl":"Komunikuj się z partnerem, aby przewidzieć odbicie i dostosować swój bieg.","uk":"Спілкуйтеся з партнером, щоб передбачити відскок і відповідно коригуйте свій біг."}'::jsonb
  ),
  (
    'cone-dribbling-slalom',
    'football_drill',
    'mid',
    '{"en":"Cone Dribbling Slalom","it":"Dribbling tra i coni slalom","pl":"Drybling przez slalom z koni","uk":"Дриблінг через кону слalom"}'::jsonb,
    '{"en":"Dribble through cones in a slalom pattern to improve ball control and agility. 1. Set up cones in a slalom pattern. 2. Start at one end and dribble through the cones. 3. Use different parts of the foot to control the ball. 4. Focus on keeping the ball close to the feet.","pl":"Przejść przez slalom z koni, wykonując drybling, aby poprawić kontrolę nad piłką i zwinność. 1. Ustawić slalom z koni. 2. Rozpocząć od jednego końca i wykonać drybling przez slalom. 3. Używać różnych części stopy do kontroli piłki. 4. Skoncentrować się na utrzymaniu piłki blisko stóp.","it":"Eseguire un dribbling attraverso i coni in un percorso a slalom per migliorare il controllo del pallone e l''agilità. 1. Disporre i coni in un percorso a slalom. 2. Iniziare da un''estremità e dribblare attraverso i coni. 3. Utilizzare diverse parti del piede per controllare il pallone. 4. Concentrarsi sul mantenere il pallone vicino ai piedi.","uk":"Пройти через кону в слаломному маршруті, виконуючи дриблінг, щоб покращити контроль над м''ячем та спритність. 1. Встановити кону в слаломному маршруті. 2. Почати з одного кінця та виконати дриблінг через кону. 3. Використовувати різні частини стопи для контролю м''яча. 4. Зосередитися на збереженні м''яча біля ніг."}'::jsonb,
    'https://www.youtube.com/watch?v=NKWlvwGcw30',
    '{"ball"}'::text[],
    8,
    12,
    99,
    '{"en":"This exercise matters because it improves ball control, agility, and speed. Famous players like Lionel Messi and Cristiano Ronaldo use similar drills to enhance their dribbling skills.","it":"Questo esercizio è importante perché migliora il controllo del pallone, l''agilità e la velocità. Giocatori famosi come Lionel Messi e Cristiano Ronaldo utilizzano esercizi simili per migliorare le loro abilità di dribbling.","pl":"Ten ćwiczenie jest ważne, ponieważ poprawia kontrolę nad piłką, zwinność i szybkość. Znani piłkarze, tacy jak Lionel Messi i Cristiano Ronaldo, korzystają z podobnych ćwiczeń, aby poprawić swoje umiejętności dryblingu.","uk":"Це вправу важливе, тому що воно покращує контроль над м''ячем, спритність та швидкість. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, використовують подібні вправи, щоб покращити свої навички дриблінгу."}'::jsonb,
    '{"en":["Ball control","Agility","Speed"],"it":["Controllo del pallone","Agilità","Velocità"],"pl":["Kontrola nad piłką","Zwinność","Szybkość"],"uk":["Контроль над м''ячем","Спритність","Швидкість"]}'::jsonb,
    '{"en":"Keep your head up and eyes forward to maintain awareness of the surroundings.","it":"Tenere la testa alta e gli occhi avanti per mantenere la consapevolezza dell''ambiente circostante.","pl":"Utrzymuj głowę do góry i oczy skierowane na przód, aby zachować świadomość otoczenia.","uk":"Тримайте голову високо та очі спрямовані вперед, щоб зберегти свідомість навколишнього середовища."}'::jsonb
  ),
  (
    'shooting-accuracy-targets',
    'football_drill',
    'mid',
    '{"en":"Shooting Accuracy Targets","it":"Tiri Precisi Bersagli","pl":"Celność Strzału Cele","uk":"Влучність Удару Мішені"}'::jsonb,
    '{"en":"Improve shooting accuracy by aiming at specific targets on the goal. 1. Set up targets on the goal, such as cones or small flags.\n2. Players take turns shooting from a designated spot, aiming for the targets.\n3. Focus on proper shooting technique and accuracy.","pl":"Popraw celność strzału poprzez wycelowanie w określone cele na bramce. 1. Umieść cele na bramce, takie jak stożki lub małe flagi.\n2. Zawodnicy po kolei wykonują strzały z wyznaczonego miejsca, celując w cele.\n3. Skoncentruj się na właściwej technice strzału i celności.","it":"Migliora la precisione dei tiri puntando a bersagli specifici sulla porta. 1. Disponi i bersagli sulla porta, come coni o piccole bandiere.\n2. I giocatori si alternano nei tiri da un punto designato, puntando ai bersagli.\n3. Concentrati sulla tecnica di tiro corretta e sulla precisione.","uk":"Покращте влучність удару, цілячись у конкретні мішені на воротах. 1. Встановіть мішені на воротах, такі як конуси або маленькі прапорці.\n2. Гравці по черзі виконують удари з позначеного місця, цілячись у мішені.\n3. Зосередьтесь на правильній техніці удару та влучності."}'::jsonb,
    'https://www.youtube.com/watch?v=cdz7nzHm6Eg',
    '{"ball"}'::text[],
    10,
    12,
    99,
    '{"en":"Shooting accuracy is crucial in football, as it can make the difference between winning and losing. Players like Cristiano Ronaldo and Lionel Messi are known for their exceptional shooting accuracy. By practicing this exercise, players can improve their chances of scoring goals.","it":"La precisione dei tiri è fondamentale nel calcio, poiché può fare la differenza tra vincere e perdere. Giocatori come Cristiano Ronaldo e Lionel Messi sono noti per la loro eccezionale precisione di tiro. Esercitandosi con questo esercizio, i giocatori possono migliorare le loro possibilità di segnare gol.","pl":"Celność strzału jest kluczowa w piłce nożnej, ponieważ może zdecydować o wygranej lub przegranej. Zawodnicy tacy jak Cristiano Ronaldo i Lionel Messi są znani ze swojej wyjątkowej celności strzału. Ćwicząc ten ćwiczenie, zawodnicy mogą poprawić swoje szanse na zdobycie gola.","uk":"Влучність удару має вирішальне значення у футболі, оскільки вона може зробити різницю між перемогою та поразкою. Гравці, такі як Крістіано Роналду та Ліонель Мессі, відомі своєю винятковою влучністю удару. Практикуючи це вправу, гравці можуть покращити свої шанси на взяття воріт."}'::jsonb,
    '{"en":["Proper shooting technique","Accuracy and precision","Ball placement"],"it":["Tecnica di tiro corretta","Precisione e accuratezza","Posizionamento della palla"],"pl":["Właściwa technika strzału","Celność i precyzja","Umieszczenie piłki"],"uk":["Правильна техніка удару","Влучність та точність","Розміщення м''яча"]}'::jsonb,
    '{"en":"Use a mix of high and low shots to keep the goalkeeper guessing.","it":"Utilizza una combinazione di tiri alti e bassi per tenere il portiere in sospeso.","pl":"Użyj mieszanych strzałów, wysokich i niskich, aby trzymać bramkarza w niepewności.","uk":"Використовуйте суміш ударів високо та низько, щоб тримати воротар у напрузі."}'::jsonb
  ),
  (
    'first-touch-receive-and-go',
    'football_drill',
    'low',
    '{"en":"First Touch Receive and Go","it":"Ricevi e Vai al Primo Tocco","pl":"Odbiór i Ruszenie z Pierwszym Dotknięciem","uk":"Прийом і Відхід з Першим Дотиком"}'::jsonb,
    '{"en":"Improve your ability to receive and immediately move with the ball. 1. Stand with a partner 5-10 yards apart. 2. The partner will pass the ball to you. 3. Focus on receiving the ball with the inside, outside, or sole of your foot, then immediately move forward with it.","pl":"Popraw swoją umiejętność odbioru i natychmiastowego ruszenia z piłką. 1. Stań z partnerem w odległości 5-10 jardów. 2. Partner poda ci piłkę. 3. Skoncentruj się na odbiorze piłki wewnętrzną, zewnętrzną lub piętą stopy, a następnie natychmiast ruszyć z nią do przodu.","it":"Migliora la tua capacità di ricevere e muoverti immediatamente con la palla. 1. Stai con un compagno a 5-10 metri di distanza. 2. Il compagno ti passerà la palla. 3. Concentrati sul ricevere la palla con l''interno, l''esterno o la suola del piede, poi muoviti immediatamente in avanti con essa.","uk":"Покращте свою здатність приймати і відразу ж рухатися з м''ячем. 1. Станьте з партнером на відстані 5-10 ярдів. 2. Партнер зробить вам передачу. 3. Зосередьтеся на прийомі м''яча внутрішньою, зовнішньою частиною стопи або підошвою, а потім відразу ж рухайтеся вперед."}'::jsonb,
    'https://www.youtube.com/watch?v=I9b21UrCnCM',
    '{"ball"}'::text[],
    6,
    12,
    99,
    '{"en":"This exercise matters because it helps improve your ball control and ability to quickly transition from receiving to moving with the ball. Many professional players, such as Lionel Messi and Cristiano Ronaldo, emphasize the importance of first-touch skills.","it":"Questo esercizio è importante perché aiuta a migliorare il controllo della palla e la capacità di passare rapidamente dal ricevere al muoversi con la palla. Molti giocatori professionisti, come Lionel Messi e Cristiano Ronaldo, sottolineano l''importanza delle abilità di primo tocco.","pl":"Ten ćwiczenie jest ważne, ponieważ pomaga poprawić kontrolę piłki i umiejętność szybkiego przejścia od odbioru do ruszenia z piłką. Wielu profesjonalnych graczy, takich jak Lionel Messi i Cristiano Ronaldo, podkreśla znaczenie umiejętności pierwszego dotknięcia.","uk":"Це вправу важливе, тому що воно допомагає покращити контроль над м''ячем та здатність швидко переходити від прийому до руху з м''ячем. Багато професійних гравців, такі як Ліонель Мессі та Кріштіану Роналду, підкреслюють важливість навичок першого дотику."}'::jsonb,
    '{"en":["Keep your head up","Use different parts of your foot","Move quickly after receiving"],"it":["Tieni la testa alta","Usa diverse parti del piede","Muoviti velocemente dopo aver ricevuto"],"pl":["Trzymaj głowę wysoko","Używaj różnych części stopy","Ruszać szybko po odbiorze"],"uk":["Тримайте голову високо","Використовуйте різні частини стопи","Рухайтеся швидко після прийому"]}'::jsonb,
    '{"en":"Practice receiving with both feet to become a more unpredictable player.","it":"Esercitati a ricevere con entrambi i piedi per diventare un giocatore più imprevedibile.","pl":"Ćwicz odbiór obiema nogami, aby stać się bardziej nieprzewidywalnym graczem.","uk":"Практикуйте прийом обома ногами, щоб стати більш непередбачуваним гравцем."}'::jsonb
  ),
  (
    'weak-foot-100-touches',
    'football_drill',
    'low',
    '{"en":"Weak Foot Touches","it":"100 tocchi piede debole","pl":"100 dotknięć słabą nogą","uk":"Сто дотиків слабкою ногою"}'::jsonb,
    '{"en":"Improve your weak foot skills with 100 touches, focusing on control and precision. 1. Stand with the ball at your feet. 2. Use the inside, outside, and sole of your weak foot to control the ball. 3. Focus on keeping the ball close to your foot. 4. Complete 100 touches, then switch to your strong foot.","pl":"Popraw swoje umiejętności słabej nogi z 100 dotknięciami, skupiając się na kontroli i precyzji. 1. Stań z piłką u twoich stóp. 2. Użyj wewnętrznej, zewnętrznej i podeszwy słabej nogi do kontrolowania piłki. 3. Skoncentruj się na utrzymaniu piłki blisko stopy. 4. Wykonaj 100 dotknięć, następnie przełącz się na silną nogę.","it":"Migliora le tue abilità con il piede debole con 100 tocchi, concentrati sul controllo e la precisione. 1. Stai con la palla ai tuoi piedi. 2. Usa l''interno, l''esterno e la suola del tuo piede debole per controllare la palla. 3. Concentrati sul tenere la palla vicino al tuo piede. 4. Completa 100 tocchi, poi passa al tuo piede forte.","uk":"Поліпшіть свої навички слабкої ноги зі 100 дотиками, зосереджуючись на контролі та точності. 1. Станьте з м''ячем біля ваших ніг. 2. Використовуйте внутрішню, зовнішню і підошву слабкої ноги для контролю м''яча. 3. Зосередьтеся на утриманні м''яча біля вашої ноги. 4. Виконайте 100 дотиків, потім переключіться на сильну ногу."}'::jsonb,
    'https://www.youtube.com/watch?v=qXAjlbb_T2g',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"This exercise helps improve your overall ball control and weak foot skills, essential for becoming a well-rounded player. Many professional players, such as Lionel Messi and Cristiano Ronaldo, emphasize the importance of developing their weak foot.","it":"Questo esercizio aiuta a migliorare il controllo della palla e le abilità con il piede debole, essenziali per diventare un giocatore completo. Molti giocatori professionisti, come Lionel Messi e Cristiano Ronaldo, sottolineano l''importanza di sviluppare il loro piede debole.","pl":"Ten ćwiczenie pomaga poprawić ogólną kontrolę piłki i umiejętności słabej nogi, co jest niezbędne do zostania wszechstronnym graczem. Wielu profesjonalnych graczy, takich jak Lionel Messi i Cristiano Ronaldo, podkreśla znaczenie rozwijania słabej nogi.","uk":"Це вправ допомагає поліпшити загальний контроль м''яча та навички слабкої ноги, що є необхідним для того, щоб стати різностороннім гравцем. Багато професійних гравців, такі як Ліонель Мессі та Кріштіану Роналду, підкреслюють важливість розвитку своєї слабкої ноги."}'::jsonb,
    '{"en":["Ball control","Weak foot precision","Keeping the ball close"],"it":["Controllo della palla","Precisione piede debole","Tenere la palla vicino"],"pl":["Kontrola piłki","Precyzja słabej nogi","Utrzymanie piłki blisko"],"uk":["Контроль м''яча","Точність слабкої ноги","Утримання м''яча біля"]}'::jsonb,
    '{"en":"Focus on using different parts of your weak foot to control the ball, and don''t be afraid to make mistakes.","it":"Concentrati sull''utilizzo di diverse parti del tuo piede debole per controllare la palla e non aver paura di commettere errori.","pl":"Skoncentruj się na używaniu różnych części słabej nogi do kontrolowania piłki i nie bój się popełniać błędów.","uk":"Зосередьтеся на використанні різних частин слабкої ноги для контролю м''яча і не бійтеся робити помилки."}'::jsonb
  ),
  (
    'juggling-progression',
    'football_drill',
    'mid',
    '{"en":"Juggling Progression","it":"Progressione di palleggio","pl":"Progresja podawania","uk":"Прогресія жонглювання"}'::jsonb,
    '{"en":"Improve ball control with a series of juggling exercises 1. Start with 10-15 reps of basic juggling using the feet and thighs. 2. Move on to alternating feet and using different parts of the body. 3. Incorporate moves like step-overs and inside cuts while juggling. 4. Finish with a series of 5-minute juggling challenges with a partner or coach.","pl":"Popraw kontrolę piłki poprzez serię ćwiczeń z podawania 1. Zacznij od 10-15 powtórzeń podstawowego podawania piłki nogami i udami. 2. Przejdź do podawania piłki na zmianę nogami i różnymi częściami ciała. 3. Wykonuj ruchy takie jak zwody i kiwki podczas podawania piłki. 4. Zakończ serią 5-minutowych wyzwań z partnerem lub trenerem.","it":"Migliora il controllo della palla con una serie di esercizi di palleggio 1. Inizia con 10-15 ripetizioni di palleggio di base usando i piedi e le cosce. 2. Passa ad alternate i piedi e usando diverse parti del corpo. 3. Incorpora mosse come step-over e tagli interni mentre palleggi. 4. Termina con una serie di sfide di palleggio di 5 minuti con un partner o un allenatore.","uk":"Поліпшіть контроль над м''ячем за допомогою серії вправ з жонглювання 1. Почніть із 10-15 повторень базового жонглювання за допомогою ніг та стегон. 2. Перейдіть до жонглювання із почерговим використанням ніг та різних частин тіла. 3. Виконуйте рухи, такі як фінти та удари під час жонглювання. 4. Закінчіть серією 5-хвилинних викликів із партнером або тренером."}'::jsonb,
    'https://www.youtube.com/watch?v=PCN8_C5IhEs',
    '{"ball"}'::text[],
    6,
    12,
    99,
    '{"en":"Juggling progression improves ball control, coordination and focus. Famous players like Lionel Messi and Cristiano Ronaldo have used juggling exercises to improve their skills.","it":"La progressione di palleggio migliora il controllo della palla, la coordinazione e la concentrazione. Giocatori famosi come Lionel Messi e Cristiano Ronaldo hanno usato esercizi di palleggio per migliorare le loro abilità.","pl":"Progresja podawania piłki poprawia kontrolę piłki, koordynację i koncentrację. Znani piłkarze tacy jak Lionel Messi i Cristiano Ronaldo używali ćwiczeń z podawania piłki, aby poprawić swoje umiejętności.","uk":"Прогресія жонглювання поліпшує контроль над м''ячем, координацію та концентрацію. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, використовували вправи з жонглювання, щоб поліпшити свої навички."}'::jsonb,
    '{"en":["Ball control","Coordination","Focus"],"it":["Controllo della palla","Coordinazione","Concentrazione"],"pl":["Kontrola piłki","Koordynacja","Koncentracja"],"uk":["Контроль над м''ячем","Координація","Концентрація"]}'::jsonb,
    '{"en":"Keep your head up and eyes forward while juggling to maintain control and awareness of your surroundings.","it":"Tieni la testa alta e gli occhi avanti mentre palleggi per mantenere il controllo e la consapevolezza dell''ambiente circostante.","pl":"Trzymaj głowę wysoko i oczy skierowane do przodu podczas podawania piłki, aby utrzymać kontrolę i świadomość otoczenia.","uk":"Тримайте голову високо та очі спрямованими вперед під час жонглювання, щоб підтримувати контроль та усвідомлення навколишнього середовища."}'::jsonb
  ),
  (
    'one-v-one-defense-stance',
    'football_drill',
    'mid',
    '{"en":"One-V-One Defense Stance","it":"Difesa uno contro uno","pl":"Obrona jeden na jeden","uk":"Захист один на один"}'::jsonb,
    '{"en":"This exercise focuses on defensive stance and reaction when facing an opponent one-on-one. 1. Divide players into pairs, with one player as the attacker and the other as the defender. 2. The attacker starts with the ball and tries to beat the defender. 3. The defender should maintain a defensive stance, with feet shoulder-width apart and body balanced.","pl":"Ten ćwiczenie koncentruje się na postawie obronnej i reakcji podczas pojedynku jeden na jeden. 1. Podziel zawodników na pary, z jednym zawodnikiem jako atakującym, a drugim jako obrońcą. 2. Atakujący zaczyna z piłką i próbuje minąć obrońcę. 3. Obrońca powinien utrzymać postawę obronną, ze stopami ułożonymi na szerokość barków i ciałem w równowadze.","it":"Questo esercizio si concentra sulla posizione difensiva e sulla reazione quando si affronta un avversario uno contro uno. 1. Dividere i giocatori in coppie, con un giocatore come attaccante e l''altro come difensore. 2. L''attaccante inizia con la palla e cerca di superare il difensore. 3. Il difensore deve mantenere una posizione difensiva, con i piedi larghi quanto le spalle e il corpo bilanciato.","uk":"Це вправа спрямована на розвиток захисної стійки та реакції під час протидії супернику один на один. 1. Розділіть гравців на пари, з одним гравцем як нападником, а іншим як захисником. 2. Нападник починає з м''ячем і намагається обігнати захисника. 3. Захисник повинен зберігати захисну стійку, з ногами на ширині плечей і тілом у рівновазі."}'::jsonb,
    'https://www.youtube.com/watch?v=LF_LD6w7DD8',
    '{"ball"}'::text[],
    8,
    12,
    99,
    '{"en":"This exercise matters because it helps defenders develop the skills and confidence to handle one-on-one situations effectively. Famous players like Sergio Ramos and Carles Puyol are known for their exceptional defensive skills.","it":"Questo esercizio è importante perché aiuta i difensori a sviluppare le abilità e la fiducia per gestire efficacemente le situazioni uno contro uno. Giocatori famosi come Sergio Ramos e Carles Puyol sono noti per le loro eccezionali abilità difensive.","pl":"To ćwiczenie jest ważne, ponieważ pomaga obrońcom rozwinąć umiejętności i pewność siebie w skutecznej obronie w sytuacjach jeden na jeden. Zawodnicy tacy jak Sergio Ramos i Carles Puyol są znani z wyjątkowych umiejętności obronnych.","uk":"Ця вправа важлива, тому що допомагає захисникам розвинути навички та впевненість у собі для ефективного захисту в ситуаціях один на один. Такі гравці, як Серхіо Рамос і Карлес Пуйоль, відомі своїми винятковими захисними навичками."}'::jsonb,
    '{"en":["Defensive stance","Reaction time","Body balance"],"it":["Posizione difensiva","Tempo di reazione","Equilibrio del corpo"],"pl":["Postawa obronna","Czas reakcji","Równowaga ciała"],"uk":["Захисна стійка","Час реакції","Рівновага тіла"]}'::jsonb,
    '{"en":"Encourage defenders to stay low and wide, with their center of gravity close to the ground.","it":"Incoraggia i difensori a rimanere bassi e larghi, con il baricentro vicino al terreno.","pl":"Zachęcać obrońców do pozostawania nisko i szeroko, z środkiem ciężkości blisko ziemi.","uk":"Заохочуйте захисників залишатися низько і широко, із центром ваги близько до землі."}'::jsonb
  ),
  (
    'long-pass-accuracy',
    'football_drill',
    'high',
    '{"en":"Long Pass Accuracy","it":"Precisione dei passaggi lunghi","pl":"Dokładność długich podań","uk":"Точність довгих передач"}'::jsonb,
    '{"en":"Improve your long pass accuracy with this challenging drill. 1. Set up two cones 20-30 yards apart. 2. Stand behind one cone with a ball. 3. Look for a teammate or target behind the other cone. 4. Pass the ball to your teammate, aiming for their feet. 5. Repeat for 10 minutes, switching roles.","pl":"Popraw swoją dokładność długich podań z pomocą tego wymagającego ćwiczenia. 1. Ustaw dwa słupki w odległości 20-30 jardów. 2. Stan za jednym słupkiem z piłką. 3. Szukaj partnera lub celu za drugim słupkiem. 4. Podaj piłkę do partnera, celując w jego nogi. 5. Powtórz przez 10 minut, zmieniając role.","it":"Migliora la precisione dei tuoi passaggi lunghi con questo esercizio impegnativo. 1. Posiziona due coni a 20-30 metri di distanza. 2. Stai dietro un cono con un pallone. 3. Cerca un compagno o un bersaglio dietro l''altro cono. 4. Passa il pallone al tuo compagno, puntando ai suoi piedi. 5. Ripeti per 10 minuti, cambiando ruolo.","uk":"Покращте точність своїх довгих передач за допомогою цього складного вправу. 1. Встановіть дві конуси на відстані 20-30 ярдів. 2. Станьте за однією конусою з м''ячем. 3. Шукайте партнера або ціль за іншою конусою. 4. Передайте м''яч партнеру, цілячись у його ноги. 5. Повторіть протягом 10 хвилин, змінюючи ролі."}'::jsonb,
    'https://www.youtube.com/watch?v=B5e7g7nrxlk',
    '{"ball"}'::text[],
    10,
    12,
    99,
    '{"en":"Long pass accuracy is crucial in football as it allows teams to quickly transition from defense to offense. Players like Beckham and Pirlo are famous for their precise long passes. Improving this skill can greatly impact your team''s performance.","it":"La precisione dei passaggi lunghi è fondamentale nel calcio poiché consente alle squadre di passare rapidamente dalla difesa all''attacco. Giocatori come Beckham e Pirlo sono famosi per i loro passaggi lunghi precisi. Migliorare questa abilità può avere un grande impatto sulle prestazioni della tua squadra.","pl":"Dokładność długich podań jest kluczowa w piłce nożnej, ponieważ pozwala drużynom szybko przechodzić od obrony do ataku. Zawodnicy tacy jak Beckham i Pirlo są znani ze swoich precyzyjnych długich podań. Poprawa tej umiejętności może znacząco wpłynąć na wyniki twojej drużyny.","uk":"Точність довгих передач є вирішальною у футболі, оскільки дозволяє командам швидко переходити від оборони до атаки. Гравці такі як Бекхем і Пірло відомі своїми точними довгими передачами. Покращення цієї навички може суттєво вплинути на виступи вашої команди."}'::jsonb,
    '{"en":["Accuracy","Power","Technique"],"it":["Precisione","Potenza","Tecnica"],"pl":["Dokładność","Siła","Technika"],"uk":["Точність","Потужність","Техніка"]}'::jsonb,
    '{"en":"Use the laces of your shoe to strike the ball for added power and accuracy.","it":"Usa i lacci delle tue scarpe per colpire il pallone e ottenere più potenza e precisione.","pl":"Użyj sznurówek buta do uderzenia piłki, aby uzyskać dodatkową siłę i dokładność.","uk":"Використовуйте шнурки свого взуття, щоб бити по м''ячу і отримати більше потужності і точності."}'::jsonb
  ),
  (
    'headers-pair-exchange',
    'football_drill',
    'mid',
    '{"en":"Header Exchange Drill","it":"Esercizio di Scambio di Testa","pl":"Ćwiczenie Wymiany Główkowania","uk":"Вправа Обміну Ударів Головою"}'::jsonb,
    '{"en":"Players practice exchanging headers in pairs, improving their ability to control and direct the ball with their heads. 1. Divide players into pairs and have them stand facing each other about 2-3 yards apart. 2. One player tosses the ball with their hands for their partner to head. 3. The partner heads the ball back to the first player, who then heads it back.","pl":"Zawodnicy ćwiczą wymianę główkowania w parach, poprawiając swoją umiejętność kontrolowania i kierowania piłki głową. 1. Podziel zawodników na pary i ustaw je naprzeciwko siebie w odległości około 2-3 metrów. 2. Jeden zawodnik rzuca piłkę rękami dla swojego partnera do główkowania. 3. Partner główkuje piłkę z powrotem do pierwszego zawodnika, który następnie główkuje ją z powrotem.","it":"I giocatori praticano scambi di testa in coppia, migliorando la loro capacità di controllare e dirigere la palla con la testa. 1. Dividere i giocatori in coppie e farli stare uno di fronte all''altro a circa 2-3 metri di distanza. 2. Un giocatore lancia la palla con le mani per il suo compagno di testa. 3. Il compagno colpisce la palla con la testa e la restituisce al primo giocatore, che la colpisce di testa.","uk":"Гравці тренують обмін ударами головою у парах, покращуючи вміння контролювати та спрямовувати м''яч головою. 1. Розділіть гравців на пари і встановіть їх один навпроти одного на відстані близько 2-3 метрів. 2. Один гравець кидає м''яч руками для свого партнера, щоб той міг вдарити головою. 3. Партнер б''є м''яч головою назад до першого гравця, який потім б''є його головою у відповідь."}'::jsonb,
    'https://www.youtube.com/watch?v=mRyMjp-1JsM',
    '{"ball"}'::text[],
    6,
    12,
    99,
    '{"en":"This exercise matters because it helps players develop their heading technique and ability to play with their head up. Many professional players, such as Cristiano Ronaldo and Robert Lewandowski, are known for their exceptional heading ability.","it":"Questo esercizio è importante perché aiuta i giocatori a sviluppare la loro tecnica di colpire di testa e la capacità di giocare con la testa alta. Molti giocatori professionisti, come Cristiano Ronaldo e Robert Lewandowski, sono noti per la loro eccezionale capacità di colpire di testa.","pl":"To ćwiczenie jest ważne, ponieważ pomaga zawodnikom rozwinąć technikę główkowania i umiejętność gry z głową do góry. Wielu profesjonalnych zawodników, takich jak Cristiano Ronaldo i Robert Lewandowski, jest znanych z ich wyjątkowej umiejętności główkowania.","uk":"Ця вправа важлива, тому що допомагає гравцям розвинути техніку ударів головою та вміння грати з піднятою головою. Багато професійних гравців, таких як Крістіано Роналду і Роберт Lewandowski, відомі своєю винятковою здатністю бити головою."}'::jsonb,
    '{"en":["Head positioning","Ball control","Communication"],"it":["Posizionamento della testa","Controllo della palla","Comunicazione"],"pl":["Pozycjonowanie głowy","Kontrola piłki","Komunikacja"],"uk":["Позиціонування голови","Контроль м''яча","Комунікація"]}'::jsonb,
    '{"en":"Encourage players to keep their eyes on the ball and use the center of their forehead to head it.","it":"Incoraggia i giocatori a tenere gli occhi sulla palla e a usarla al centro della fronte per colpirla.","pl":"Zachęcać zawodników do trzymania oczu na piłce i używania środka czoła do główkowania.","uk":"Заохочуйте гравців тримати очі на м''ячі та використовувати центр чола для ударів головою."}'::jsonb
  ),
  (
    'finishing-first-time',
    'football_drill',
    'high',
    '{"en":"Finishing First Time","pl":"Wykańczanie pierwszym dotykiem","it":"Tiro al volo","uk":"Удар з першого дотику"}'::jsonb,
    '{"en":"This exercise focuses on shooting technique and accuracy when finishing with the first touch. 1. Set up a series of cones or small goals in a line. 2. Players start at one end and dribble towards the goals. 3. As they approach each goal, they must shoot first-time with the inside, outside, and instep of their foot.","pl":"Ten ćwiczenie koncentruje się na technice strzału i precyzji przy wykańczaniu pierwszym dotykiem. 1. Ustaw szereg stożków lub małych bramek w linii. 2. Gracze zaczynają z jednego końca i dryblują w stronę bramek. 3. Gdy podchodzą do każdej bramki, muszą strzelić pierwszym dotykiem z użyciem wewnętrznej, zewnętrznej i górnej części stopy.","it":"Questo esercizio si concentra sulla tecnica di tiro e sulla precisione nel tiro al volo. 1. Disponi una serie di coni o piccole porte in linea. 2. I giocatori iniziano da un''estremità e dribblano verso le porte. 3. Quando si avvicinano a ogni porta, devono tirare al volo con la parte interna, esterna e centrale del piede.","uk":"Це вправа спрямована на техніку удару та точність при ударі з першого дотику. 1. Установіть ряд конусів або маленьких воріт у лінії. 2. Гравці починають з одного кінця і дриблюють до воріт. 3. Коли вони підходять до кожних воріт, вони повинні бити з першого дотику внутрішньою, зовнішньою та середньою частиною ступні."}'::jsonb,
    'https://www.youtube.com/watch?v=3VXG1ihKjg0',
    '{"ball"}'::text[],
    10,
    12,
    99,
    '{"en":"This exercise matters because it improves a player''s ability to score goals in game-like situations. Many professional players, such as Cristiano Ronaldo and Robert Lewandowski, emphasize the importance of finishing first-time.","pl":"To ćwiczenie ma znaczenie, ponieważ poprawia umiejętność zawodnika do strzelania goli w sytuacjach podobnych do meczowych. Wielu profesjonalnych graczy, takich jak Cristiano Ronaldo i Robert Lewandowski, podkreśla znaczenie wykańczania pierwszym dotykiem.","it":"Questo esercizio è importante perché migliora la capacità del giocatore di segnare gol in situazioni simili a quelle di gioco. Molti giocatori professionisti, come Cristiano Ronaldo e Robert Lewandowski, enfatizzano l''importanza del tiro al volo.","uk":"Ця вправа важлива, тому що покращує здатність гравця забивати голи у ситуаціях, подібних до ігрових. Багато професійних гравців, такі як Крістіано Роналду і Роберт Lewandowski, підкреслюють важливість удару з першого дотику."}'::jsonb,
    '{"en":["Ball control","Shooting technique","Accuracy"],"pl":["Kontrola piłki","Technika strzału","Precyzja"],"it":["Controllo della palla","Tecnica di tiro","Precisione"],"uk":["Контроль м''яча","Техніка удару","Точність"]}'::jsonb,
    '{"en":"Encourage players to stay focused and composed under pressure to get the best results.","pl":"Zachęcaj graczy do pozostania skoncentrowanymi i opanowanymi pod presją, aby osiągnąć najlepsze rezultaty.","it":"Incoraggia i giocatori a rimanere concentrati e composti sotto pressione per ottenere i migliori risultati.","uk":"Заохочуйте гравців залишатися зосередженими та зібраними під тиском, щоб досягти найкращих результатів."}'::jsonb
  ),
  (
    'set-piece-corner-delivery',
    'football_drill',
    'mid',
    '{"en":"Corner Kick Delivery","it":"Calcio d''angolo","pl":"Podanie z rzutu rożnego","uk":"Кутовий удар"}'::jsonb,
    '{"en":"Practice delivering the ball into the box from a corner kick. Focus on accuracy and ball placement. 1. Stand behind the corner flag with a ball. 2. Practice different types of deliveries (e.g. short, long, driven). 3. Focus on using the laces or inside of the foot for control.","pl":"Ćwicz podanie piłki w pole karne z rzutu rożnego. Skoncentruj się na precyzji i umieszczeniu piłki. 1. Stań za chorągiewką narożną z piłką. 2. Ćwicz różne rodzaje podań (np. krótkie, długie, mocne). 3. Skoncentruj się na użyciu sznurówek lub wewnętrznej strony stopy do kontroli.","it":"Esercitazione per consegnare la palla nella box da calcio d''angolo. Concentrati su precisione e posizionamento della palla. 1. Stai dietro la bandiera d''angolo con una palla. 2. Esercitati con diversi tipi di consegne (ad es. corto, lungo, tirato). 3. Concentrati sull''uso dei lacci o dell''interno del piede per il controllo.","uk":"Практикуйте подання м''яча у штрафну зону з кутового удару. Зосередьтеся на точності та розміщенні м''яча. 1. Станьте за кутовим прапорцем із м''ячем. 2. Практикуйте різні види подань (наприклад, коротке, довге, ударне). 3. Зосередьтеся на використанні шнурівок або внутрішньої сторони стопи для контролю."}'::jsonb,
    'https://www.youtube.com/watch?v=8r6sM47lN4M',
    '{"ball"}'::text[],
    8,
    12,
    99,
    '{"en":"Corner kicks are a crucial part of set-piece strategy. Players like David Beckham and Trent Alexander-Arnold are renowned for their exceptional delivery from corners.","it":"I calci d''angolo sono una parte cruciale della strategia dei calci da fermo. Giocatori come David Beckham e Trent Alexander-Arnold sono rinomati per la loro eccezionale consegna dai calci d''angolo.","pl":"Rzuty rożne są kluczową częścią strategii rzutów stałych. Zawodnicy tacy jak David Beckham i Trent Alexander-Arnold są znani ze swojej wyjątkowej precyzji przy podaniach z rzutów rożnych.","uk":"Кутові удари є важливою частиною стратегії стандартних положень. Гравці, такі як Девід Бекхем та Трент Александер-Арнольд, відомі своєю винятковою подачею з кутових ударів."}'::jsonb,
    '{"en":["Accuracy","Ball placement","Control"],"it":["Precisione","Posizionamento della palla","Controllo"],"pl":["Precyzja","Umieszczenie piłki","Kontrola"],"uk":["Точність","Розміщення м''яча","Контроль"]}'::jsonb,
    '{"en":"Use different parts of the foot to achieve varying levels of spin and pace on the ball.","it":"Usa diverse parti del piede per ottenere livelli diversi di spin e velocità sulla palla.","pl":"Użyj różnych części stopy, aby uzyskać różne poziomy rotacji i prędkości piłki.","uk":"Використовуйте різні частини стопи, щоб досягти різних рівнів обертання та швидкості м''яча."}'::jsonb
  ),
  (
    'agility-t-drill',
    'football_drill',
    'mid',
    '{"en":"Agility T-Drill","it":"Esercizio T di agilità","pl":"Ćwiczenie T - zwinność","uk":"Вправа Т - сприт"}'::jsonb,
    '{"en":"Improve speed, agility and reaction time with this T-shaped drill. 1. Set up a T shape with cones. 2. Start at the base of the T. 3. Sprint to the top of the T, then quickly change direction and sprint to one side. 4. Quickly change direction again and sprint back to the base of the T. 5. Repeat on the other side.","pl":"Popraw szybkość, zwinność i czas reakcji dzięki temu ćwiczeniu w kształcie litery T. 1. Ustaw kształt T z pachołków. 2. Zacznij u podstawy T. 3. Biegnij do góry T, następnie szybko zmień kierunek i biegnij na jedną stronę. 4. Szybko zmień kierunek ponownie i biegnij z powrotem do podstawy T. 5. Powtórz po drugiej stronie.","it":"Migliora velocità, agilità e tempo di reazione con questo esercizio a forma di T. 1. Crea una forma di T con i coni. 2. Inizia dalla base della T. 3. Corri verso la cima della T, poi cambia rapidamente direzione e corri verso un lato. 4. Cambia rapidamente direzione di nuovo e corri indietro verso la base della T. 5. Ripeti dall''altro lato.","uk":"Покращте швидкість, сприт і час реакції за допомогою цієї вправи у формі літери Т. 1. Установіть форму Т з конусів. 2. Почніть біля основи Т. 3. Біжіть до вершини Т, потім швидко змініть напрямок і біжіть в один бік. 4. Швидко змініть напрямок знову і біжіть назад до основи Т. 5. Повторіть з іншого боку."}'::jsonb,
    'https://www.youtube.com/watch?v=BgFwLnNl91I',
    '{}'::text[],
    5,
    12,
    99,
    '{"en":"This exercise improves agility, speed and reaction time. Players like Lionel Messi and Cristiano Ronaldo use agility drills like this to stay quick on their feet.","it":"Questo esercizio migliora l''agilità, la velocità e il tempo di reazione. Giocatori come Lionel Messi e Cristiano Ronaldo utilizzano esercizi di agilità come questo per rimanere veloci sui piedi.","pl":"To ćwiczenie poprawia zwinność, szybkość i czas reakcji. Zawodnicy tacy jak Lionel Messi i Cristiano Ronaldo korzystają z ćwiczeń zwinności takich jak to, aby pozostać szybkimi na nogach.","uk":"Ця вправа покращує сприт, швидкість і час реакції. Гравці такі як Ліонель Мессі та Кріштіану Роналду використовують вправи на сприт як цю, щоб залишатися швидкими на ногах."}'::jsonb,
    '{"en":["Quick changes of direction","Fast acceleration and deceleration","Good reaction time"],"it":["Cambiamenti rapidi di direzione","Accelerazione e decelerazione veloci","Buon tempo di reazione"],"pl":["Szybkie zmiany kierunku","Szybkie przyspieszenie i zwalnianie","Dobry czas reakcji"],"uk":["Швидкі зміни напрямку","Швидке прискорення і сповільнення","Хороший час реакції"]}'::jsonb,
    '{"en":"Focus on explosive acceleration and deceleration to get the most out of this drill.","it":"Concentrati sull''accelerazione e decelerazione esplosiva per ottenere il massimo da questo esercizio.","pl":"Skup się na wybuchowym przyspieszeniu i zwalnianiu, aby uzyskać jak najwięcej z tego ćwiczenia.","uk":"Зосередьтеся на вибуховому прискоренні і сповільненні, щоб отримати максимум від цієї вправи."}'::jsonb
  ),
  (
    'cruyff-turn',
    'football_trick',
    'mid',
    '{"en":"Cruyff Turn","it":"Giro di Cruyff","pl":"Zwod Cruyffa","uk":"Поворот Кройффа"}'::jsonb,
    '{"en":"A move to deceive an opponent by pretending to pass the ball, then quickly turning to continue dribbling. 1. Start with the ball at your feet.\n2. Pretend to pass the ball by moving your leg as if you''re kicking it.\n3. As you do this, shift your body weight onto the foot that''s not kicking the ball.\n4. Quickly turn 180 degrees, using the inside of your foot to control the ball.","pl":"Zwod, który oszukuje przeciwnika poprzez udawanie podania piłki, a następnie szybki zwrot, aby kontynuować drybling. 1. Zacznij z piłką u twoich stóp.\n2. Udawaj, że podajesz piłkę, poruszając nogą, jakbyś ją kopał.\n3. Podczas gdy to robisz, przesuń swój ciężar ciała na nogę, która nie kopie piłki.\n4. Szybko wykonaj obrót o 180 stopni, używając wewnętrznej strony stopy do kontroli piłki.","it":"Una mossa per ingannare un avversario fingendo di passare la palla, poi girandosi rapidamente per continuare a dribblare. 1. Inizia con la palla ai tuoi piedi.\n2. Fingi di passare la palla muovendo la gamba come se stessi calciando.\n3. Mentre fai questo, sposta il tuo peso corporeo sul piede che non sta calciando la palla.\n4. Gira rapidamente di 180 gradi, usando l''interno del piede per controllare la palla.","uk":"Прийом, щоб обдурити суперника, імітуючи передачу м''яча, а потім швидко повертаючись, щоб продовжити ведення м''яча. 1. Почніть з м''ячем біля ваших ніг.\n2. Імітуйте підання м''яча, рухаючи ногою, ніби ви її б''єте.\n3. Під час цього змістіть свій центр ваги на ногу, яка не б''є м''яч.\n4. Швидко виконайте поворот на 180 градусів, використовуючи внутрішню сторону стопи для контролю м''яча."}'::jsonb,
    'https://www.youtube.com/watch?v=NySWdgkfQNk',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The Cruyff Turn is a valuable skill for any footballer, allowing them to quickly change direction and deceive opponents. Many top players, including Lionel Messi and Cristiano Ronaldo, have used this move to great effect.","it":"Il giro di Cruyff è una abilità preziosa per qualsiasi calciatore, permettendogli di cambiare rapidamente direzione e ingannare gli avversari. Molti giocatori di alto livello, tra cui Lionel Messi e Cristiano Ronaldo, hanno usato questa mossa con grande effetto.","pl":"Zwod Cruyffa jest cenną umiejętnością dla każdego piłkarza, pozwalającą mu szybko zmienić kierunek i oszukać przeciwników. Wielu najlepszych graczy, w tym Lionel Messi i Cristiano Ronaldo, wykorzystali ten zwod z dużym efektem.","uk":"Поворот Кройффа - це цінний навик для будь-якого футболіста, що дозволяє йому швидко змінювати напрямок і обдурювати суперників. Багато топових гравців, включаючи Ліонеля Мессі та Кріштіану Роналду, використовували цей прийом із великим ефектом."}'::jsonb,
    '{"en":["Weight transfer","Ball control","Speed of movement"],"it":["Trasferimento del peso","Controllo della palla","Velocità di movimento"],"pl":["Przesunięcie ciężaru ciała","Kontrola piłki","Prędkość ruchu"],"uk":["Перенос центру ваги","Контроль м''яча","Швидкість руху"]}'::jsonb,
    '{"en":"Keep your eyes up and focused on the opponent to sell the fake pass.","it":"Tieni gli occhi in alto e concentrati sull''avversario per vendere il passaggio falso.","pl":"Trzymaj oczy w górze i skup się na przeciwniku, aby sprzedać fałszywe podanie.","uk":"Тримайте очі вгорі та зосередьтесь на супернику, щоб продати фальшиву передачу."}'::jsonb
  ),
  (
    'step-over',
    'football_trick',
    'mid',
    '{"en":"Step Over","it":"Finta Laterale","pl":"Zwod Bokiem","uk":"Бічний Фінт"}'::jsonb,
    '{"en":"The step over is a move used to deceive an opponent by pretending to move the ball in one direction while actually moving it in another. This exercise helps improve ball control and deception techniques. 1. Start with the ball at your feet and an imaginary opponent in front of you. 2. Step over the ball with one foot, keeping your knee straight. 3. Quickly move the ball to the side with the inside of your foot, using the step over motion to deceive the opponent. 4. Practice with both feet to improve your overall skill.","pl":"Zwod bokiem to ruch używany do oszukania przeciwnika, udając że piłka porusza się w jednym kierunku, a w rzeczywistości porusza się w innym. Ćwiczenie to pomaga poprawić kontrolę nad piłką i techniki zwodu. 1. Zacznij z piłką u twoich stóp i wyimaginowanym przeciwnikiem przed tobą. 2. Zrób krok bokiem nad piłkę jednym nogą, trzymając kolano proste. 3. Szybko przesuń piłkę na bok wewnętrzną częścią stopy, używając ruchu zwodu do oszukania przeciwnika. 4. Ćwicz z obu nogami, aby poprawić swoją ogólną umiejętność.","it":"La finta laterale è un movimento utilizzato per ingannare un avversario, fingendo di muovere la palla in una direzione mentre la si muove in un''altra. Questo esercizio aiuta a migliorare il controllo della palla e le tecniche di inganno. 1. Inizia con la palla ai tuoi piedi e un avversario immaginario davanti a te. 2. Fai un passo laterale sopra la palla con un piede, tenendo il ginocchio dritto. 3. Sposta rapidamente la palla sul lato con l''interno del piede, usando il movimento di finta per ingannare l''avversario. 4. Esercitati con entrambi i piedi per migliorare la tua abilità generale.","uk":"Бічний фінт - це рух, який використовується для обману суперника, імітуючи рух м''яча в одному напрямку, а насправді переміщаючи його в іншому. Це вправа допомагає поліпшити контроль над м''ячем та техніку обману. 1. Почніть з м''ячем біля ваших ніг та уявним суперником перед вами. 2. Зробіть крок боком над м''ячем однією ногою, тримаючи коліно прямим. 3. Швидко перемістіть м''яч на бік внутрішньою частиною стопи, використовуючи рух фінта для обману суперника. 4. Практикуйте з обома ногами, щоб поліпшити вашу загальну майстерність."}'::jsonb,
    'https://www.youtube.com/watch?v=8KFRX0wAuEM',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The step over is an essential skill for any football player, as it allows you to create space and get past opponents. Many professional players, such as Lionel Messi and Cristiano Ronaldo, have mastered this move and use it to great effect on the pitch.","it":"La finta laterale è un''abilità essenziale per qualsiasi giocatore di calcio, poiché consente di creare spazio e superare gli avversari. Molti giocatori professionisti, come Lionel Messi e Cristiano Ronaldo, hanno padroneggiato questo movimento e lo utilizzano con grande efficacia sul campo.","pl":"Zwod bokiem jest niezbędną umiejętnością dla każdego piłkarza, ponieważ pozwala stworzyć przestrzeń i minąć przeciwników. Wielu zawodników profesjonalnych, takich jak Lionel Messi i Cristiano Ronaldo, opanowało ten ruch i używa go z dużym efektem na boisku.","uk":"Бічний фінт є необхідним навичком для будь-якого футболіста, оскільки дозволяє створювати простір та обіходити суперників. Багато професійних гравців, таких як Ліонель Мессі та Кріштіану Роналду, оволоділи цим рухом та використовують його з великим ефектом на полі."}'::jsonb,
    '{"en":["Ball control","Deception technique","Quick movement"],"it":["Controllo della palla","Tecnica di inganno","Movimento rapido"],"pl":["Kontrola piłki","Technika zwodu","Szybki ruch"],"uk":["Контроль м''яча","Техніка обману","Швидкий рух"]}'::jsonb,
    '{"en":"Keep your eyes on the ball and focus on the movement of your feet to execute the step over smoothly.","it":"Tieni gli occhi sulla palla e concentrati sul movimento dei tuoi piedi per eseguire la finta laterale in modo fluido.","pl":"Trzymaj oczy na piłce i skup się na ruchu swoich stóp, aby wykonać zwod bokiem płynnie.","uk":"Тримайте очі на м''ячі та зосередьтесь на русі ваших ніг, щоб виконати бічний фінт плавно."}'::jsonb
  ),
  (
    'scissors-double-touch',
    'football_trick',
    'mid',
    '{"en":"Scissors Double Touch","pl":"Nożyce Podwójny Dotyk","it":"Forbice Doppio Tocco","uk":"Ножиці Подвійний Торк"}'::jsonb,
    '{"en":"This exercise helps players master the scissors move with a double touch to confuse opponents. 1. Start with the ball at your feet. 2. Perform a scissors move by lifting one foot and moving it around the ball. 3. Quickly make a second touch to change direction. 4. Practice with both feet.","pl":"Ten ćwiczenie pomaga zawodnikom opanować ruch nożycami z podwójnym dotykiem, aby zmylić przeciwników. 1. Zacznij z piłką u stóp. 2. Wykonaj ruch nożycami, unosząc jedną nogę i poruszając nią wokół piłki. 3. Szybko wykonaj drugi dotyk, aby zmienić kierunek. 4. Ćwicz z obu nóg.","it":"Questo esercizio aiuta i giocatori a padroneggiare la mossa forbice con doppio tocco per confondere gli avversari. 1. Inizia con la palla ai piedi. 2. Esegui un movimento a forbice sollevando un piede e muovendolo intorno alla palla. 3. Fai rapidamente un secondo tocco per cambiare direzione. 4. Esercitati con entrambi i piedi.","uk":"Це вправа допомагає гравцям опанувати рух ножицями з подвійним торком, щоб здивувати суперників. 1. Почніть з м''ячем біля ніг. 2. Виконайте рух ножицями, піднімаючи одну ногу і рухаючи нею навколо м''яча. 3. Швидко виконайте другий торк, щоб змінити напрямок. 4. Практикуйте обома ногами."}'::jsonb,
    'https://www.youtube.com/watch?v=lEv7QTRJC2Q',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The scissors double touch is a valuable skill for players to master as it allows them to quickly change direction and confuse opponents. Famous players like Lionel Messi and Neymar have used this move to great effect.","pl":"Ruch nożycami z podwójnym dotykiem to cenna umiejętność, którą zawodnicy powinni opanować, ponieważ pozwala im szybko zmienić kierunek i zmylić przeciwników. Zawodnicy tacy jak Lionel Messi i Neymar wielokrotnie używali tego ruchu z dużym efektem.","it":"La forbice con doppio tocco è un''abilità preziosa per i giocatori da padroneggiare poiché consente loro di cambiare rapidamente direzione e confondere gli avversari. Giocatori famosi come Lionel Messi e Neymar hanno usato questa mossa con grande effetto.","uk":"Рух ножицями з подвійним торком - це цінна вміння, яку гравці повинні опанувати, оскільки вона дозволяє їм швидко змінити напрямок і здивувати суперників. Такі гравці, як Ліонель Мессі та Неймар, використовували цей рух із великим ефектом."}'::jsonb,
    '{"en":["Ball control","Foot movement","Direction change"],"pl":["Kontrola piłki","Ruch nogą","Zmiana kierunku"],"it":["Controllo della palla","Movimento del piede","Cambiamento di direzione"],"uk":["Контроль м''яча","Рух ногою","Зміна напрямку"]}'::jsonb,
    '{"en":"Focus on keeping your movements quick and light to sell the fake and create space.","pl":"Skup się na utrzymaniu szybkich i lekkich ruchów, aby sprzedać fałszywy ruch i stworzyć przestrzeń.","it":"Concentrati sul mantenere i movimenti veloci e leggeri per vendere il finto e creare spazio.","uk":"Зосередьтеся на збереженні швидких і легких рухів, щоб продати фінт і створити простір."}'::jsonb
  ),
  (
    'elastico',
    'football_trick',
    'high',
    '{"en":"Elastico","it":"Elastico","pl":"Elastico","uk":"Еластіко"}'::jsonb,
    '{"en":"The elastico is a advanced move used to deceive an opponent by quickly changing the direction of the ball. To perform the elastico, follow these steps:\n1. Start by standing with the ball at your feet.\n2. Move your foot in a small circle around the ball, using the inside and outside of your foot.\n3. As you move your foot, shift your body weight to generate power and momentum.\n4. Quickly change the direction of the ball by flicking your foot in the opposite direction.","pl":"Elastico to zaawansowany ruch używany do oszukania przeciwnika poprzez szybką zmianę kierunku piłki. Aby wykonać elastico, postępuj zgodnie z poniższymi krokami:\n1. Zacznij od stania z piłką u twoich stóp.\n2. Poruszaj stopą w małym okręgu wokół piłki, używając wewnętrznej i zewnętrznej strony stopy.\n3. Podczas poruszania stopą, przesuwaj ciężar ciała, aby wygenerować siłę i pęd.\n4. Szybko zmień kierunek piłki, uderzając stopą w przeciwnym kierunku.","it":"L''elastico è un movimento avanzato usato per ingannare un avversario cambiando rapidamente la direzione del pallone. Per eseguire l''elastico, segui questi passaggi:\n1. Inizia standoti con il pallone ai tuoi piedi.\n2. Muovi il tuo piede in un piccolo cerchio intorno al pallone, usando l''interno e l''esterno del piede.\n3. Mentre muovi il piede, sposta il tuo peso corporeo per generare potenza e slancio.\n4. Cambia rapidamente la direzione del pallone facendo scattare il piede nella direzione opposta.","uk":"Еластіко - це складний рух, який використовується для обману суперника шляхом швидкої зміни напрямку м''яча. Щоб виконати еластіко, дотримуйтесь цих кроків:\n1. Почніть зі стояння з м''ячем біля ваших ніг.\n2. Рухайте стопою по малому колу навколо м''яча, використовуючи внутрішню та зовнішню сторону стопи.\n3. Під час руху стопи, зміщуйте вагу тіла, щоб генерувати силу та імпульс.\n4. Швидко змініть напрямок м''яча, клацнувши стопою у протилежному напрямку."}'::jsonb,
    'https://www.youtube.com/watch?v=AALdtkH5oUk',
    '{"ball"}'::text[],
    6,
    12,
    99,
    '{"en":"The elastico is a valuable skill for any football player, as it allows you to quickly change direction and deceive opponents. Many professional players, such as Cristiano Ronaldo and Ronaldinho, have used the elastico to great effect on the pitch.","it":"L''elastico è un''abilità preziosa per qualsiasi giocatore di calcio, poiché consente di cambiare rapidamente direzione e ingannare gli avversari. Molti giocatori professionisti, come Cristiano Ronaldo e Ronaldinho, hanno usato l''elastico con grande effetto sul campo.","pl":"Elastico to cenna umiejętność dla każdego piłkarza, ponieważ pozwala szybko zmienić kierunek i oszukać przeciwników. Wielu profesjonalnych graczy, takich jak Cristiano Ronaldo i Ronaldinho, używało elastico z dużym efektem na boisku.","uk":"Еластіко - це цінна навичка для будь-якого футболіста, оскільки дозволяє швидко змінити напрямок та обманути суперників. Багато професійних гравців, такі як Крістіано Роналду та Роналдінью, використовували еластіко з великим ефектом на полі."}'::jsonb,
    '{"en":["Ball control","Foot movement","Weight transfer","Direction change"],"it":["Controllo del pallone","Movimento del piede","Trasferimento del peso","Cambiamento di direzione"],"pl":["Kontrola piłki","Ruch stopy","Przesunięcie ciężaru","Zmiana kierunku"],"uk":["Контроль м''яча","Рух стопи","Зміщення ваги","Зміна напрямку"]}'::jsonb,
    '{"en":"Practice the elastico in both directions to become a more unpredictable player.","it":"Esegui l''elastico in entrambe le direzioni per diventare un giocatore più imprevedibile.","pl":"Ćwicz elastico w obu kierunkach, aby stać się bardziej nieprzewidywalnym graczem.","uk":"Практикуйте еластіко в обох напрямках, щоб стати більш непередбачуваним гравцем."}'::jsonb
  ),
  (
    'rabona',
    'football_trick',
    'high',
    '{"en":"Rabona","it":"Rabona","pl":"Rabona","uk":"Рабона"}'::jsonb,
    '{"en":"The rabona is a football trick where a player uses the outside of their foot to pass or shoot the ball. To perform a rabona, follow these steps:\n1. Approach the ball at an angle.\n2. Plant your non-kicking foot next to the ball.\n3. Swing your kicking leg around the back of your standing leg, using the outside of your foot to strike the ball.\n4. Follow through with your kicking leg.","pl":"Rabona to trik piłkarski, w którym zawodnik używa zewnętrznej strony stopy do podania lub strzału piłki. Aby wykonać rabonę, wykonaj następujące kroki:\n1. Zbliż się do piłki pod kątem.\n2. Ustaw nogę niekopiącą obok piłki.\n3. Zamachnij nogą kopiącą wokół tylnej części nogi podpierającej, używając zewnętrznej strony stopy do uderzenia piłki.\n4. Kontynuuj ruch nogą kopiącą.","it":"La rabona è un trucco calcistico in cui un giocatore usa l''esterno del piede per passare o tirare la palla. Per eseguire una rabona, segui questi passaggi:\n1. Avvicinati alla palla con un angolo.\n2. Pianta il piede non calciante accanto alla palla.\n3. Fai oscillare la gamba calciante intorno alla parte posteriore della gamba di sostegno, usando l''esterno del piede per colpire la palla.\n4. Segui con la gamba calciante.","uk":"Рабона - це футбольний трюк, коли гравець використовує зовнішню сторону стопи для пасу або удару по м''ячу. Щоб виконати рабону, дотримуйтесь цих кроків:\n1. Підійдіть до м''яча під кутом.\n2. Поставте не ударну ногу біля м''яча.\n3. Розгойдуйте ударну ногу навколо задньої частини опорної ноги, використовуючи зовнішню сторону стопи для удару по м''ячу.\n4. Продовжіть рух ударної ноги."}'::jsonb,
    'https://www.youtube.com/watch?v=jGcS4_mC_5g',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The rabona is a valuable skill for football players to master, as it allows them to deceive opponents and create scoring opportunities. Famous players like Juan Román Riquelme and Lionel Messi have used the rabona to great effect.","it":"La rabona è un''abilità preziosa per i giocatori di calcio da padroneggiare, poiché consente loro di ingannare gli avversari e creare opportunità di segnare. Giocatori famosi come Juan Román Riquelme e Lionel Messi hanno usato la rabona con grande effetto.","pl":"Rabona to cenna umiejętność dla piłkarzy, którą warto opanować, ponieważ pozwala im oszukać przeciwników i stworzyć okazje do zdobycia gola. Zawodnicy tacy jak Juan Román Riquelme i Lionel Messi używali rabony z dużym efektem.","uk":"Рабона - це цінна навичка для футболістів, яку варто опанувати, оскільки вона дозволяє їм обманювати суперників та створювати можливості для забивання голів. Такі гравці, як Хуан Роман Рікelme та Ліонель Мессі, використовували рабону з великим ефектом."}'::jsonb,
    '{"en":["Use the outside of your foot","Keep your ankle locked","Follow through with your kicking leg"],"it":["Usa l''esterno del piede","Tieni la caviglia bloccata","Segui con la gamba calciante"],"pl":["Użyj zewnętrznej strony stopy","Zablokuj kostkę","Kontynuuj ruch nogą kopiącą"],"uk":["Використовуйте зовнішню сторону стопи","Зафіксуйте гомілку","Продовжіть рух ударної ноги"]}'::jsonb,
    '{"en":"Practice the rabona with both feet to become a more unpredictable player.","it":"Esercitati con la rabona con entrambi i piedi per diventare un giocatore più imprevedibile.","pl":"Ćwicz rabonę obiema nogami, aby stać się bardziej nieprzewidywalnym zawodnikiem.","uk":"Практикуйте рабону обома ногами, щоб стати більш непередбачуваним гравцем."}'::jsonb
  ),
  (
    'rainbow-flick',
    'football_trick',
    'high',
    '{"en":"Rainbow Flick","it":"Flick di Rainbow","pl":"Rzut tęczowy","uk":"Дощовий удар"}'::jsonb,
    '{"en":"The rainbow flick is a skill move that involves flicking the ball up and over an opponent using the inside of the foot. To perform a rainbow flick, follow these steps:\n1. Start by dribbling the ball with the inside of your foot.\n2. As you approach the opponent, flick the ball up and over them using the inside of your foot.\n3. Keep your ankle locked and use your toes to control the ball.\n4. Practice the move in both directions to master it.","pl":"Rzut tęczowy to technika, która polega na podniesieniu piłki i przejęciu jej nad przeciwnikiem przy użyciu wewnętrznej strony stopy. Aby wykonać rzut tęczowy, wykonaj następujące kroki:\n1. Zacznij od dryblingu piłki wewnętrzną stroną stopy.\n2. Gdy zbliżasz się do przeciwnika, podnieś piłkę i przejdź nad nim przy użyciu wewnętrznej strony stopy.\n3. Trzymaj kostkę unieruchomioną i użyj palców u stóp do kontroli piłki.\n4. Ćwicz ruch w obu kierunkach, aby go opanować.","it":"Il flick di rainbow è una mossa di abilità che consiste nel sollevare la palla e superarla un avversario usando l''interno del piede. Per eseguire un flick di rainbow, segui questi passaggi:\n1. Inizia dribblando la palla con l''interno del piede.\n2. Quando ti avvicini all''avversario, solleva la palla e superala usando l''interno del piede.\n3. Tieni la caviglia bloccata e usa le dita dei piedi per controllare la palla.\n4. Esercitati nella mossa in entrambe le direzioni per padroneggiarla.","uk":"Дощовий удар - це технічний прийом, який полягає у піднятті м''яча та перекиданні його над суперником із використанням внутрішньої сторони стопи. Щоб виконати дощовий удар, виконайте такі кроки:\n1. Почніть із дribbling м''яча внутрішньою стороною стопи.\n2. Коли ви наближаєтесь до суперника, підніміть м''яч та перекиньте його над ним із використанням внутрішньої сторони стопи.\n3. Тримайте кісточку нерухомою та використовуйте пальці ніг для контролю м''яча.\n4. Практикуйте рух в обох напрямках, щоб його освоїти."}'::jsonb,
    'https://www.youtube.com/watch?v=KrYAlcXKErw',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The rainbow flick is a valuable skill for any football player, as it allows them to beat opponents and create scoring opportunities. Many professional players, such as Neymar and Ronaldinho, have used this move to great effect.","it":"Il flick di rainbow è un''abilità preziosa per qualsiasi giocatore di calcio, poiché consente di superare gli avversari e creare opportunità di segnare. Molti giocatori professionisti, come Neymar e Ronaldinho, hanno usato questa mossa con grande efficacia.","pl":"Rzut tęczowy to cenna umiejętność dla każdego piłkarza, ponieważ pozwala mu na pokonanie przeciwników i stworzenie okazji do zdobycia gola. Wielu profesjonalnych graczy, takich jak Neymar i Ronaldinho, używało tej techniki z dużym powodzeniem.","uk":"Дощовий удар - це цінний технічний прийом для будь-якого футболіста, оскільки він дозволяє йому обіграти суперників та створити можливості для взяття воріт. Багато професійних гравців, такі як Неймар та Роналдінью, використовували цей прийом з великим ефектом."}'::jsonb,
    '{"en":["Ball control","Ankle stability","Opponent deception"],"it":["Controllo della palla","Stabilità della caviglia","Inganno dell''avversario"],"pl":["Kontrola piłki","Stabilność kostki","Oszukiwanie przeciwnika"],"uk":["Контроль м''яча","Стабільність кісточки","Обман суперника"]}'::jsonb,
    '{"en":"Practice the rainbow flick in game-like situations to improve your timing and effectiveness.","it":"Esercitati nel flick di rainbow in situazioni simili a quelle di gioco per migliorare il tuo tempismo e la tua efficacia.","pl":"Ćwicz rzut tęczowy w sytuacjach podobnych do meczowych, aby poprawić swoje wyczucie czasu i skuteczność.","uk":"Практикуйте дощовий удар у ігрових ситуаціях, щоб поліпшити свій таймінг та ефективність."}'::jsonb
  ),
  (
    'maradona-spin',
    'football_trick',
    'high',
    '{"en":"Maradona Spin","it":"Rotazione di Maradona","pl":"Obrót Maradony","uk":"Обертання Марадони"}'::jsonb,
    '{"en":"A high-level move that involves a 360-degree spin while keeping the ball close to your feet. 1. Start with the ball at your feet and your body balanced evenly. 2. Shift your weight onto one foot and use the other to perform a small step-back. 3. Rotate your body 360 degrees while keeping the ball close to your feet using the inside, outside, and sole of your foot. 4. Practice with both feet to master the move.","pl":"Wysoki poziom trudności, wykonywanie obrotu o 360 stopni, trzymając piłkę blisko stóp. 1. Zacznij z piłką u stóp i ciałem równomiernie zrównoważonym. 2. Przesuń ciężar ciała na jedną nogę i użyj drugiej do wykonania małego kroku w tył. 3. Wykonaj obrót ciała o 360 stopni, trzymając piłkę blisko stóp, używając wewnętrznej, zewnętrznej i podeszwy stopy. 4. Ćwicz z obu nóg, aby opanować ten ruch.","it":"Una mossa di alto livello che prevede una rotazione di 360 gradi tenendo la palla vicina ai piedi. 1. Inizia con la palla ai piedi e il corpo bilanciato uniformemente. 2. Sposta il peso su un piede e usa l''altro per eseguire un piccolo passo indietro. 3. Ruota il corpo di 360 gradi tenendo la palla vicina ai piedi usando l''interno, l''esterno e la pianta del piede. 4. Esercitati con entrambi i piedi per padroneggiare la mossa.","uk":"Високий рівень складності, виконання обертання на 360 градусів, тримаючи м''яч біля ніг. 1. Почніть з м''ячем біля ніг і тілом рівномірно збалансованим. 2. Перенесіть вагу на одну ногу і використайте іншу для виконання маленького кроку назад. 3. Виконайте обертання тіла на 360 градусів, тримаючи м''яч біля ніг, використовуючи внутрішню, зовнішню і підошву стопи. 4. Практикуйте з обох ніг, щоб опанувати цей рух."}'::jsonb,
    'https://www.youtube.com/watch?v=YJgRq-tQtAU',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The Maradona Spin is a highly effective move that can help you evade defenders and create scoring opportunities. Many professional players, including Diego Maradona and Lionel Messi, have successfully used this move in their games.","it":"La rotazione di Maradona è una mossa molto efficace che può aiutarti a eludere i difensori e creare opportunità di segnare. Molti giocatori professionisti, tra cui Diego Maradona e Lionel Messi, hanno utilizzato con successo questa mossa nelle loro partite.","pl":"Obrót Maradony jest bardzo skutecznym ruchem, który może pomóc ci uniknąć obrońców i stworzyć możliwości zdobycia gola. Wielu zawodników, w tym Diego Maradona i Lionel Messi, skutecznie wykorzystali ten ruch w swoich meczach.","uk":"Обертання Марадони - це дуже ефективний рух, який може допомогти вам уникнути захисників і створити можливості для забивання голу. Багато професійних гравців, включаючи Дієго Марадону і Ліонеля Мессі, успішно використовували цей рух у своїх іграх."}'::jsonb,
    '{"en":["Weight transfer","Ball control","Speed and agility"],"it":["Trasferimento del peso","Controllo della palla","Velocità e agilità"],"pl":["Przeniesienie ciężaru ciała","Kontrola piłki","Prędkość i zwinność"],"uk":["Перенесення ваги тіла","Контроль м''яча","Швидкість і спритність"]}'::jsonb,
    '{"en":"Keep your center of gravity low and your eyes on the ball to maintain control throughout the spin.","it":"Tieni il tuo baricentro basso e gli occhi sulla palla per mantenere il controllo durante la rotazione.","pl":"Utrzymuj niski środek ciężkości i patrz na piłkę, aby zachować kontrolę podczas obrotu.","uk":"Тримайте свій центр ваги низько і дивитесь на м''яч, щоб зберегти контроль під час обертання."}'::jsonb
  ),
  (
    'fake-shot',
    'football_trick',
    'mid',
    '{"en":"Fake Shot","it":"Tiro Finto","pl":"Fałszywy Strzał","uk":"Фальшивий Удар"}'::jsonb,
    '{"en":"A move to deceive the opponent by pretending to shoot the ball. This exercise helps improve ball control and deception skills. 1. Start with the ball at your feet.\n2. Take a few steps back to create space.\n3. Pretend to shoot the ball by swinging your leg and following through with your motion.\n4. As you do this, keep your eyes on the ball and maintain control.\n5. Quickly move the ball in a different direction to deceive your opponent.","pl":"Ruch mający na celu oszukać przeciwnika poprzez udawanie strzału. Ćwiczenie to pomaga poprawić kontrolę nad piłką oraz umiejętności zwodzenia. 1. Zacznij z piłką u twoich stóp.\n2. Zrób kilka kroków do tyłu, aby stworzyć przestrzeń.\n3. Udawaj strzał, wymachując nogą i kontynuując ruch.\n4. Podczas tego utrzymuj wzrok na piłce i kontrolę.\n5. Szybko przesuń piłkę w innym kierunku, aby oszukać przeciwnika.","it":"Una mossa per ingannare l''avversario fingendo di tirare la palla. Questo esercizio aiuta a migliorare il controllo della palla e le abilità di inganno. 1. Inizia con la palla ai tuoi piedi.\n2. Fai alcuni passi indietro per creare spazio.\n3. Fingi di tirare la palla facendo oscillare la gamba e continuando con il movimento.\n4. Mentre fai questo, tieni gli occhi sulla palla e mantieni il controllo.\n5. Sposta rapidamente la palla in una direzione diversa per ingannare il tuo avversario.","uk":"Цей рух спрямований на те, щоб обманути суперника імітацією удару. Це вправ допомагає покращити контроль над м''ячем та навички обману. 1. Почніть з м''ячем біля ваших ніг.\n2. Зробіть декілька кроків назад, щоб створити простір.\n3. Імітуйте удар, махаючи ногою і продовжуючи рух.\n4. Під час цього утримуйте погляд на м''ячі та контроль.\n5. Швидко перемістіть м''яч в іншому напрямку, щоб обманути суперника."}'::jsonb,
    'https://www.youtube.com/watch?v=yPdW1Pdq0Z8',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"This exercise matters because it helps players develop deception skills, which are essential for beating opponents in one-on-one situations. Famous players like Lionel Messi and Cristiano Ronaldo are known for their mastery of fake shots.","it":"Questo esercizio è importante perché aiuta i giocatori a sviluppare abilità di inganno, che sono essenziali per battere gli avversari in situazioni di uno contro uno. Giocatori famosi come Lionel Messi e Cristiano Ronaldo sono noti per la loro maestria nei tiri finti.","pl":"To ćwiczenie jest ważne, ponieważ pomaga zawodnikom rozwinąć umiejętności zwodzenia, które są niezbędne do pokonania przeciwników w sytuacjach jeden na jeden. Zawodnicy tacy jak Lionel Messi i Cristiano Ronaldo są znani ze swojego mistrzostwa w wykonywaniu fałszywych strzałów.","uk":"Це вправ є важливою, тому що допомагає гравцям розвинути навички обману, які є необхідними для перемоги над суперниками у ситуаціях один на один. Такі гравці, як Ліонель Мессі та Кріштіану Роналду, відомі своїм вмінням виконувати фальшиві удари."}'::jsonb,
    '{"en":["Ball control","Deception","Quick movement"],"it":["Controllo della palla","Inganno","Movimento rapido"],"pl":["Kontrola piłki","Zwodzenie","Szybki ruch"],"uk":["Контроль над м''ячем","Обман","Швидкий рух"]}'::jsonb,
    '{"en":"Remember to keep your eyes on the ball and maintain a calm demeanor to sell the fake shot.","it":"Ricorda di tenere gli occhi sulla palla e di mantenere un atteggiamento calmo per rendere credibile il tiro finto.","pl":"Pamiętaj, aby utrzymać wzrok na piłce i zachować spokojne nastawienie, aby sprzedać fałszywy strzał.","uk":"Пам''ятайте, щоб утримувати погляд на м''ячі та зберігати спокійний вигляд, щоб зробити фальшивий удар переконливим."}'::jsonb
  ),
  (
    'body-feint',
    'football_trick',
    'low',
    '{"en":"Body Feint","it":"Finta di Corpo","pl":"Zwod Ciała","uk":"Фінт Тіла"}'::jsonb,
    '{"en":"A simple move to deceive an opponent by shifting your body weight. 1. Start with the ball at your feet.\n2. Shift your body weight onto one foot, keeping the other foot free.\n3. Quickly move your body weight to the other foot, making a fake movement with the ball.","pl":"Prosty zwód ciała, aby oszukać przeciwnika. 1. Zacznij z piłką u twoich stóp.\n2. Przesuń ciężar ciała na jedną nogę, trzymając drugą nogę wolną.\n3. Szybko przesuń ciężar ciała na drugą nogę, wykonując fałszywy ruch piłką.","it":"Un movimento semplice per ingannare un avversario spostando il peso del corpo. 1. Inizia con la palla ai tuoi piedi.\n2. Sposta il peso del corpo su un piede, tenendo l''altro piede libero.\n3. Sposta rapidamente il peso del corpo sull''altro piede, facendo un movimento finto con la palla.","uk":"Простий фінт тіла, щоб обдурити суперника. 1. Почніть з м''ячем біля ваших ніг.\n2. Перенесіть вагу тіла на одну ногу, тримаючи іншу ногу вільною.\n3. Швидко перенесіть вагу тіла на іншу ногу, виконуючи фальшивий рух м''ячем."}'::jsonb,
    'https://www.youtube.com/watch?v=WAEPmQM3K7g',
    '{"ball"}'::text[],
    4,
    12,
    99,
    '{"en":"The body feint is a fundamental movement in football that can help you create space and confuse opponents. Many professional players, such as Lionel Messi and Cristiano Ronaldo, use this move to great effect.","it":"La finta di corpo è un movimento fondamentale nel calcio che può aiutarti a creare spazio e confondere gli avversari. Molti giocatori professionisti, come Lionel Messi e Cristiano Ronaldo, utilizzano questo movimento con grande efficacia.","pl":"Zwod ciała jest podstawowym ruchem w piłce nożnej, który może pomóc ci stworzyć przestrzeń i zmylić przeciwników. Wielu profesjonalnych graczy, takich jak Lionel Messi i Cristiano Ronaldo, używa tego ruchu z dużym efektem.","uk":"Фінт тіла - це базовий рух у футболі, який може допомогти вам створити простір і збентежити суперників. Багато професійних гравців, такі як Ліонель Мессі та Кріштіану Роналду, використовують цей рух із великим ефектом."}'::jsonb,
    '{"en":["Weight transfer","Body movement","Ball control"],"it":["Trasferimento del peso","Movimento del corpo","Controllo della palla"],"pl":["Przeniesienie ciężaru","Ruch ciała","Kontrola piłki"],"uk":["Перенесення ваги","Рух тіла","Контроль м''яча"]}'::jsonb,
    '{"en":"Practice the body feint in different directions to improve your overall game.","it":"Esegui la finta di corpo in diverse direzioni per migliorare il tuo gioco complessivo.","pl":"Ćwicz zwód ciała w różnych kierunkach, aby poprawić swoją ogólną grę.","uk":"Практикуйте фінт тіла у різних напрямках, щоб покращити свою загальну гру."}'::jsonb
  ),
  (
    'drag-back',
    'football_trick',
    'low',
    '{"en":"Drag Back","it":"Tiro indietro","pl":"Zwod tyłem","uk":"Відволікання назад"}'::jsonb,
    '{"en":"A basic move to deceive an opponent by dragging the ball back with the sole of the foot. 1. Start with the ball at your feet.\n2. Use the sole of one foot to drag the ball back, keeping your knee slightly bent.\n3. As you drag the ball back, shift your weight onto the other foot.\n4. Practice with both feet to master the move.","pl":"Podstawowy zwód, aby oszukać przeciwnika poprzez kiwnięcie piłki tyłem. 1. Zacznij z piłką u twoich stóp.\n2. Użyj podeszwy jednego stopy, aby kiwnąć piłkę tyłem, trzymając kolano lekko zgięte.\n3. Gdy kiwasz piłkę, przesuń ciężar ciała na drugą stopę.\n4. Ćwicz z obu stron, aby opanować ten zwód.","it":"Un movimento di base per ingannare un avversario tirando indietro la palla con la suola del piede. 1. Inizia con la palla ai tuoi piedi.\n2. Usa la suola di un piede per tirare indietro la palla, tenendo il ginocchio leggermente piegato.\n3. Mentre tiri indietro la palla, sposta il tuo peso sull''altro piede.\n4. Esercitati con entrambi i piedi per padroneggiare il movimento.","uk":"Базовий трюк, щоб обдурити суперника відволіканням м''яча назад. 1. Почніть з м''ячем біля ваших ніг.\n2. Використайте підошву однієї ноги, щоб відволікти м''яч назад, тримаючи коліно трохи зігнутим.\n3. Коли відволікаєте м''яч, перенесіть вагу тіла на іншу ногу.\n4. Тренуйтеся обома ногами, щоб опанувати цей трюк."}'::jsonb,
    'https://www.youtube.com/watch?v=jhCJUbsiYE0',
    '{"ball"}'::text[],
    4,
    12,
    99,
    '{"en":"The drag back is a fundamental move in football that can help you create space and deceive opponents. Many professional players, such as Lionel Messi and Cristiano Ronaldo, have mastered this move. By practicing the drag back, you can improve your ball control and become a more effective player.","it":"Il tiro indietro è un movimento fondamentale nel calcio che può aiutarti a creare spazio e ingannare gli avversari. Molti giocatori professionisti, come Lionel Messi e Cristiano Ronaldo, hanno padroneggiato questo movimento. Esercitando il tiro indietro, puoi migliorare il tuo controllo della palla e diventare un giocatore più efficace.","pl":"Zwod tyłem jest podstawowym ruchem w piłce nożnej, który może pomóc ci stworzyć przestrzeń i oszukać przeciwników. Wielu profesjonalnych graczy, takich jak Lionel Messi i Cristiano Ronaldo, opanowało ten zwód. Ćwicząc zwod tyłem, możesz poprawić kontrolę nad piłką i stać się bardziej efektywnym graczem.","uk":"Відволікання назад - це базовий трюк у футболі, який може допомогти вам створити простір і обдурити суперників. Багато професійних гравців, такі як Ліонель Мессі і Кріштіану Роналду, опанували цей трюк. Тренуючи відволікання назад, ви можете покращити контроль над м''ячем і стати більш ефективним гравцем."}'::jsonb,
    '{"en":["Ball control","Weight transfer","Deception"],"it":["Controllo della palla","Trasferimento del peso","Inganno"],"pl":["Kontrola piłki","Przesunięcie ciężaru","Oszustwo"],"uk":["Контроль м''яча","Перенесення ваги","Обдурення"]}'::jsonb,
    '{"en":"Keep your head up and eyes forward while performing the drag back to maintain awareness of your surroundings.","it":"Tieni la testa alta e gli occhi avanti mentre esegui il tiro indietro per mantenere la consapevolezza dell''ambiente circostante.","pl":"Trzymaj głowę wysoko i oczy skierowane do przodu podczas wykonywania zwodu tyłem, aby utrzymać świadomość otoczenia.","uk":"Тримайте голову високо і очі спрямованими вперед під час виконання відволікання назад, щоб підтримувати усвідомлення оточення."}'::jsonb
  ),
  (
    'la-croqueta',
    'football_trick',
    'mid',
    '{"en":"La Croqueta","it":"La Croqueta","pl":"La Croqueta","uk":"Ла Крокета"}'::jsonb,
    '{"en":"A move to deceive an opponent by pushing the ball with the inside of one foot and then quickly pulling it back with the other foot. 1. Start with the ball at your feet. 2. Push the ball with the inside of one foot. 3. Quickly pull the ball back with the other foot. 4. Practice with both feet.","pl":"Zwodzenie przeciwnika poprzez pchanie piłki wewnętrzną częścią stopy, a następnie szybkie pociągnięcie jej z powrotem drugą nogą. 1. Zacznij z piłką u swoich stóp. 2. Pchnij piłkę wewnętrzną częścią stopy. 3. Szybko pociągnij piłkę z powrotem drugą nogą. 4. Ćwicz z obu nóg.","it":"Un movimento per ingannare un avversario spingendo la palla con l''interno di un piede e poi tirandola rapidamente indietro con l''altro piede. 1. Inizia con la palla ai tuoi piedi. 2. Spingi la palla con l''interno di un piede. 3. Tira rapidamente la palla indietro con l''altro piede. 4. Esercitati con entrambi i piedi.","uk":"Рух для обману суперника шляхом проштовхування м''яча внутрішньою частиною стопи однієї ноги, а потім швидкого підтягування його назад іншою ногою. 1. Почніть з м''ячем біля своїх ніг. 2. Проштовхніть м''яч внутрішньою частиною стопи однієї ноги. 3. Швидко підтягніть м''яч назад іншою ногою. 4. Практикуйте обома ногами."}'::jsonb,
    'https://www.youtube.com/watch?v=qaGYZsffPNg',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"This move helps to deceive opponents and create space on the field. Famous players like Lionel Messi and Neymar have used La Croqueta to great effect.","it":"Questo movimento aiuta a ingannare gli avversari e a creare spazio sul campo. Giocatori famosi come Lionel Messi e Neymar hanno usato La Croqueta con grande effetto.","pl":"Ten zwód pomaga oszukać przeciwników i stworzyć przestrzeń na boisku. Zawodnicy tacy jak Lionel Messi i Neymar używali La Croqueta z dużym skutkiem.","uk":"Цей рух допомагає обманути суперників та створити простір на полі. Такі відомі гравці, як Ліонель Мессі та Неймар, використовували Ла Крокета з великим ефектом."}'::jsonb,
    '{"en":["Ball control","Speed and agility","Deception technique"],"it":["Controllo della palla","Velocità e agilità","Tecnica di inganno"],"pl":["Kontrola piłki","Prędkość i zwinność","Technika zwodu"],"uk":["Контроль м''яча","Швидкість та спритність","Техніка обману"]}'::jsonb,
    '{"en":"Practice La Croqueta in game-like situations to improve your reaction time and decision-making.","it":"Esercitati con La Croqueta in situazioni simili a quelle di gioco per migliorare il tuo tempo di reazione e la tua capacità di prendere decisioni.","pl":"Ćwicz La Croqueta w sytuacjach podobnych do meczowych, aby poprawić swój czas reakcji i umiejętność podejmowania decyzji.","uk":"Практикуйте Ла Крокета у ігрових ситуаціях, щоб поліпшити свій час реакції та вміння приймати рішення."}'::jsonb
  ),
  (
    'no-look-pass',
    'football_trick',
    'high',
    '{"en":"No Look Pass","it":"Passaggio senza guardare","pl":"Podanie bez patrzenia","uk":"Передача без погляду"}'::jsonb,
    '{"en":"A deceptive passing technique where the player looks away from the target while passing the ball. 1. Start by standing with the ball and looking away from your target.\n2. Use the inside of your foot to push the ball in the direction of your target.\n3. As you pass, keep your head and eyes looking away from the target to sell the deception.\n4. Practice with both feet to master the technique.","pl":"Oszukała technika podania, gdzie zawodnik spogląda z dala od celu podczas podawania piłki. 1. Zacznij od stania z piłką i patrzenia z dala od celu.\n2. Użyj wewnętrznej strony stopy, aby popchnąć piłkę w kierunku celu.\n3. Podczas podania trzymaj głowę i oczy z dala od celu, aby sprzedać oszustwo.\n4. Ćwicz z obu nóg, aby opanować technikę.","it":"Una tecnica di passaggio ingannevole in cui il giocatore guarda lontano dal bersaglio mentre passa la palla. 1. Inizia standoti con la palla e guardando lontano dal tuo bersaglio.\n2. Usa l''interno del piede per spingere la palla nella direzione del tuo bersaglio.\n3. Mentre passi, tieni la testa e gli occhi lontani dal bersaglio per vendere l''inganno.\n4. Esercitati con entrambi i piedi per padroneggiare la tecnica.","uk":"Обманювальна техніка передачі, коли гравець дивиться в інший бік від цілі під час передачі м''яча. 1. Почніть із стояння з м''ячем і поглядом у інший бік від цілі.\n2. Використайте внутрішню сторону стопи, щоб проштовхнути м''яч у напрямку цілі.\n3. Під час передачі тримайте голову і очі відвернутими від цілі, щоб створити ілюзію.\n4. Практикуйте з обох ніг, щоб опанувати техніку."}'::jsonb,
    'https://www.youtube.com/watch?v=gffsAaXEK_M',
    '{"ball"}'::text[],
    5,
    12,
    99,
    '{"en":"The no-look pass is a valuable skill for any footballer, as it allows them to deceive opponents and create scoring opportunities. Many top players, such as Lionel Messi and Cristiano Ronaldo, have mastered this technique.","it":"Il passaggio senza guardare è un''abilità preziosa per qualsiasi calciatore, poiché consente loro di ingannare gli avversari e creare opportunità di segnare. Molti giocatori di alto livello, come Lionel Messi e Cristiano Ronaldo, hanno padroneggiato questa tecnica.","pl":"Podanie bez patrzenia to cenna umiejętność dla każdego piłkarza, ponieważ pozwala mu oszukać przeciwników i stworzyć okazje do zdobycia gola. Wielu najlepszych graczy, takich jak Lionel Messi i Cristiano Ronaldo, opanowało tę technikę.","uk":"Передача без погляду - це цінна навичка для будь-якого футболіста, оскільки дозволяє йому обманювати суперників і створювати можливості для забивання голів. Багато топових гравців, такі як Ліонель Мессі і Кріштіану Роналду, опанували цю техніку."}'::jsonb,
    '{"en":["Deception with body positioning","Weight and accuracy of pass","Speed and reaction of opponent"],"it":["Inganno con il posizionamento del corpo","Peso e precisione del passaggio","Velocità e reazione dell''avversario"],"pl":["Oszustwo z pozycjonowaniem ciała","Waga i dokładność podania","Prędkość i reakcja przeciwnika"],"uk":["Обман із позиціонуванням тіла","Вага і точність передачі","Швидкість і реакція суперника"]}'::jsonb,
    '{"en":"Practice the no-look pass with a teammate or friend to improve your technique and timing.","it":"Esercitati al passaggio senza guardare con un compagno di squadra o un amico per migliorare la tua tecnica e il tuo tempismo.","pl":"Ćwicz podanie bez patrzenia z kolegą z drużyny lub znajomym, aby poprawić swoją technikę i wyczucie czasu.","uk":"Практикуйте передачу без погляду із партнером або другом, щоб поліпшити свою техніку і відчуття часу."}'::jsonb
  ),
  (
    'one-v-one-mini-goals',
    'football_game',
    'mid',
    '{"en":"1v1 Mini Goals","it":"Porta piccola 1v1","pl":"Mini cele 1 na 1","uk":"Міні цілі 1 на 1"}'::jsonb,
    '{"en":"Improve your one-on-one skills with a defender in a small goal scenario. 1. Set up two mini goals facing each other, 5-6 yards apart.\n2. Players start at opposite ends of the goals.\n3. The attacker tries to score in the opponent''s goal, while the defender tries to prevent it.","pl":"Popraw swoje umiejętności gry 1 na 1 z obrońcą w scenariuszu z mini bramkami. 1. Ustaw dwie mini bramki naprzeciw siebie, w odległości 5-6 jardów.\n2. Zawodnicy zaczynają u przeciwnych końców bramek.\n3. Napastnik próbuje strzelić gola w bramce przeciwnika, podczas gdy obrońca próbuje temu zapobiec.","it":"Migliora le tue abilità uno contro uno con un difensore in un piccolo scenario di porta. 1. Disponi due porte piccole una di fronte all''altra, a 5-6 metri di distanza.\n2. I giocatori iniziano dalle estremità opposte delle porte.\n3. L''attaccante cerca di segnare nella porta dell''avversario, mentre il difensore cerca di impedirlo.","uk":"Покращте свої навички гри 1 на 1 із захисником у сценарії з міні цілями. 1. Встановіть дві міні цілі одна навпроти одної, на відстані 5-6 ярдів.\n2. Гравці починають із протилежних кінців цілей.\n3. Нападник намагається забити гол у воротах суперника, тоді як захисник намагається цьому завадити."}'::jsonb,
    'https://www.youtube.com/watch?v=u_QvGswOJxc',
    '{"ball"}'::text[],
    12,
    12,
    99,
    '{"en":"This exercise helps improve your ball control, decision-making, and ability to beat a defender in a tight space. Famous players like Lionel Messi and Cristiano Ronaldo excel in one-on-one situations.","it":"Questo esercizio aiuta a migliorare il controllo della palla, la presa di decisioni e la capacità di superare un difensore in uno spazio stretto. Giocatori famosi come Lionel Messi e Cristiano Ronaldo eccellono nelle situazioni uno contro uno.","pl":"Ten ćwiczenie pomaga poprawić kontrolę piłki, podejmowanie decyzji i umiejętność wyprzedzania obrońcy w ciasnej przestrzeni. Znani piłkarze tacy jak Lionel Messi i Cristiano Ronaldo wyróżniają się w sytuacjach 1 na 1.","uk":"Це вправ допомагає покращити контроль над м''ячем, прийняття рішень та здатність обіграти захисника у тісному просторі. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, відмінно діють у ситуаціях 1 на 1."}'::jsonb,
    '{"en":["Ball control","Speed and agility","Decision-making"],"it":["Controllo della palla","Velocità e agilità","Presa di decisioni"],"pl":["Kontrola piłki","Prędkość i zwinność","Podejmowanie decyzji"],"uk":["Контроль над м''ячем","Швидкість та гнучкість","Прийняття рішень"]}'::jsonb,
    '{"en":"Keep your head up and eyes forward to stay aware of your surroundings and make quick decisions.","it":"Tieni la testa alta e gli occhi avanti per rimanere consapevole dell''ambiente circostante e prendere decisioni rapide.","pl":"Trzymaj głowę wysoko i oczy do przodu, aby być świadomym otoczenia i podejmować szybkie decyzje.","uk":"Тримайте голову високо та очі вперед, щоб бути обізнаним із оточенням та приймати швидкі рішення."}'::jsonb
  ),
  (
    'two-v-two-possession-rondo',
    'football_game',
    'mid',
    '{"en":"Two-v-Two Possession Rondo","it":"Rondo di Possesso 2v2","pl":"Rondo Posesyjne 2 na 2","uk":"Рондо володіння 2 на 2"}'::jsonb,
    '{"en":"A small-sided game focusing on maintaining possession in tight spaces. 1. Divide players into two teams of two.\n2. The objective is for one team to maintain possession while the other team tries to win the ball back.\n3. The team in possession must stay within a designated area.","pl":"Gra polegająca na utrzymaniu piłki w małych przestrzeniach. 1. Podziel zawodników na dwa zespoły po dwa.\n2. Celem jest utrzymanie piłki przez jeden zespół, podczas gdy drugi zespół próbuje ją odzyskać.\n3. Zespół z piłką musi pozostać w wyznaczonym obszarze.","it":"Un gioco a squadre ristrette che si concentra sul mantenimento del possesso palla negli spazi stretti. 1. Dividere i giocatori in due squadre di due.\n2. L''obiettivo è che una squadra mantenga il possesso mentre l''altra cerca di riconquistare la palla.\n3. La squadra in possesso deve rimanere all''interno di un''area designata.","uk":"Гра на володіння м''ячем у маленьких просторах. 1. Розділити гравців на дві команди по два.\n2. Мета - одна команда зберігає володіння м''ячем, інша команда намагається відібрати м''яч.\n3. Команда з м''ячем повинна залишатися в межах визначеної зони."}'::jsonb,
    'https://www.youtube.com/watch?v=ESEjTbZxs90',
    '{"ball"}'::text[],
    12,
    12,
    99,
    '{"en":"This exercise improves players'' ability to maintain possession under pressure, a crucial skill in football. Famous players like Lionel Messi and Andres Iniesta excelled in such situations.","it":"Questo esercizio migliora la capacità dei giocatori di mantenere il possesso sotto pressione, un''abilità cruciale nel calcio. Giocatori famosi come Lionel Messi e Andres Iniesta eccellevano in tali situazioni.","pl":"Ten ćwiczenie poprawia umiejętność zawodników do utrzymania piłki pod presją, co jest kluczową umiejętnością w piłce nożnej. Zawodnicy tacy jak Lionel Messi i Andres Iniesta byli znani z tego, że potrafili utrzymać piłkę w trudnych sytuacjach.","uk":"Ця вправа покращує здатність гравців зберігати володіння м''ячем під тиском, що є важливою навичкою у футболі. Відомі гравці, такі як Ліонель Мессі та Андреас Інієста, вміли зберігати володіння м''ячем у складних ситуаціях."}'::jsonb,
    '{"en":["Communication","Movement off the ball","Quick decision-making"],"it":["Comunicazione","Movimento senza palla","Decisione rapida"],"pl":["Komunikacja","Ruch bez piłki","Szybka decyzja"],"uk":["Комунікація","Рух без м''яча","Швидке прийняття рішень"]}'::jsonb,
    '{"en":"Encourage players to stay calm and focused, using their peripheral vision to maintain awareness of their surroundings.","it":"Incoraggia i giocatori a rimanere calmi e concentrati, usando la loro visione periferica per mantenere la consapevolezza dell''ambiente circostante.","pl":"Zachęcać zawodników do pozostania spokojnymi i skoncentrowanymi, wykorzystując swój peryferyjny wzrok do utrzymania świadomości otoczenia.","uk":"Заохочуйте гравців залишатися спокійними та зосередженими, використовуючи свій периферійний зір для підтримання усвідомлення оточення."}'::jsonb
  ),
  (
    'three-v-three-mini-match',
    'football_game',
    'mid',
    '{"en":"3v3 Mini Match","it":"Partita 3 contro 3","pl":"Mecz 3 na 3","uk":"Міні-матч 3 на 3"}'::jsonb,
    '{"en":"A small-sided game to practice team play and strategy in a condensed space. 1. Divide players into teams of three. 2. Set up a small playing area, approximately 20x30 yards. 3. Start a 15-minute match, with teams playing against each other.","pl":"Gra zespołowa, aby ćwiczyć grę zespołową i strategię w ograniczonej przestrzeni. 1. Podzielić zawodników na zespoły trzyosobowe. 2. Ustawić mały obszar gry, około 20x30 jardów. 3. Rozpocząć 15-minutowy mecz, z zespołami grającymi przeciwko sobie.","it":"Un gioco a squadre per allenare il gioco di squadra e la strategia in uno spazio ristretto. 1. Dividere i giocatori in squadre di tre. 2. Preparare un''area di gioco piccola, circa 20x30 yard. 3. Iniziare un match di 15 minuti, con le squadre che giocano l''una contro l''altra.","uk":"Командна гра для тренування командної гри та стратегії у обмеженому просторі. 1. Розділити гравців на команди по три особи. 2. Підготувати невелику ігрову зону, приблизно 20x30 ярдів. 3. Почати 15-хвилинний матч, з командами, що грають одна проти одної."}'::jsonb,
    'https://www.youtube.com/watch?v=PT5GjuVT83I',
    '{"ball"}'::text[],
    15,
    12,
    99,
    '{"en":"This exercise matters because it helps improve team coordination, spatial awareness, and decision-making under pressure. Famous players like Lionel Messi and Cristiano Ronaldo have used similar drills to enhance their skills.","it":"Questo esercizio è importante perché aiuta a migliorare la coordinazione della squadra, la consapevolezza spaziale e la presa di decisioni sotto pressione. Giocatori famosi come Lionel Messi e Cristiano Ronaldo hanno usato esercizi simili per migliorare le loro abilità.","pl":"Ten ćwiczenie jest ważne, ponieważ pomaga poprawić koordynację zespołu, świadomość przestrzenną i podejmowanie decyzji pod presją. Znani piłkarze, tacy jak Lionel Messi i Cristiano Ronaldo, używali podobnych ćwiczeń, aby poprawić swoje umiejętności.","uk":"Це вправа важлива, тому що допомагає покращити командну координацію, просторове сприйняття та прийняття рішень під тиском. Відомі гравці, такі як Ліонель Мессі та Кріштіану Роналду, використовували подібні вправи, щоб покращити свої навички."}'::jsonb,
    '{"en":["Team coordination","Spatial awareness","Quick decision-making"],"it":["Coordinazione della squadra","Consapevolezza spaziale","Pronta decisione"],"pl":["Koordynacja zespołu","Świadomość przestrzenna","Szybkie podejmowanie decyzji"],"uk":["Командна координація","Просторове сприйняття","Швидке прийняття рішень"]}'::jsonb,
    '{"en":"Encourage players to communicate effectively and make tactical decisions quickly.","it":"Incoraggiare i giocatori a comunicare efficacemente e prendere decisioni tattiche velocemente.","pl":"Zachęcić zawodników do skutecznej komunikacji i szybkiego podejmowania decyzji taktycznych.","uk":"Заохочувати гравців до ефективної комунікації та швидкого прийняття тактичних рішень."}'::jsonb
  ),
  (
    'world-cup-tournament',
    'football_game',
    'high',
    '{"en":"World Cup Tournament Drill","it":"Esercizio Torneo Mondiale","pl":"Ćwiczenie Turniej Światowy","uk":"Вправа Світовий Турнір"}'::jsonb,
    '{"en":"Simulate a World Cup tournament with small-sided games and varying conditions. 1. Divide players into teams of 3-4. 2. Set up a series of small-sided games (e.g., 3v3, 4v4) on a reduced field. 3. Each game lasts 5-7 minutes, with a 2-minute rest between games. 4. Change game conditions (e.g., add defenders, reduce space) after each round.","pl":"Symulacja turnieju światowego z małymi zespołami i zmiennymi warunkami. 1. Podziel zawodników na zespoły 3-4 osobowe. 2. Ustaw szereg małych gier (np. 3x3, 4x4) na mniejszym polu. 3. Każda gra trwa 5-7 minut, z 2-minutową przerwą między grami. 4. Zmieniaj warunki gry (np. dodaj obrońców, zmniejsz przestrzeń) po każdej rundzie.","it":"Simulare un torneo mondiale con partite a squadre ridotte e condizioni variabili. 1. Dividere i giocatori in squadre di 3-4. 2. Allestire una serie di partite a squadre ridotte (ad esempio 3v3, 4v4) su un campo ridotto. 3. Ogni partita dura 5-7 minuti, con 2 minuti di riposo tra le partite. 4. Cambiare le condizioni di gioco (ad esempio aggiungere difensori, ridurre lo spazio) dopo ogni turno.","uk":"Симулюйте світовий турнір із зменшеними іграми та змінними умовами. 1. Розділіть гравців на команди по 3-4 чоловіки. 2. Установіть серію ігор зі зменшеними командами (наприклад 3х3, 4х4) на зменшеному полі. 3. Кожна гра триває 5-7 хвилин, із 2-хвилинним відпочинком між іграми. 4. Змінюйте умови гри (наприклад додайте захисників, зменшіть простір) після кожного раунду."}'::jsonb,
    'https://www.youtube.com/watch?v=Y4Bcjp5q8m0',
    '{"ball"}'::text[],
    20,
    12,
    99,
    '{"en":"This exercise improves decision-making, adaptability, and game awareness. Famous players like Lionel Messi and Cristiano Ronaldo have used similar drills to enhance their skills.","it":"Questo esercizio migliora la presa di decisione, l''adattabilità e la consapevolezza del gioco. Giocatori famosi come Lionel Messi e Cristiano Ronaldo hanno utilizzato esercizi simili per migliorare le loro abilità.","pl":"To ćwiczenie poprawia umiejętność podejmowania decyzji, adaptację i świadomość gry. Znani piłkarze tacy jak Lionel Messi i Cristiano Ronaldo używali podobnych ćwiczeń, aby poprawić swoje umiejętności.","uk":"Ця вправа покращує вміння приймати рішення, адаптивність та усвідомлення гри. Відомі гравці такі як Ліонель Мессі та Кріштіану Роналду використовували подібні вправи, щоб покращити свої навички."}'::jsonb,
    '{"en":["Quick decision-making","Adaptability to changing conditions","Effective communication"],"it":["Pronta presa di decisione","Adattabilità alle condizioni variabili","Comunicazione efficace"],"pl":["Szybkie podejmowanie decyzji","Adaptacja do zmieniających się warunków","Skuteczna komunikacja"],"uk":["Швидке прийняття рішень","Адаптивність до змінних умов","Ефективна комунікація"]}'::jsonb,
    '{"en":"Encourage players to stay focused and composed under pressure, just like in a real World Cup tournament.","it":"Incoraggiare i giocatori a rimanere concentrati e composti sotto pressione, proprio come in un vero torneo mondiale.","pl":"Zachęcać zawodników do pozostania skoncentrowanymi i opanowanymi pod presją, jak w prawdziwym turnieju światowym.","uk":"Заохочуйте гравців залишатися зосередженими та зібраними під тиском, як на справжньому світовому турнірі."}'::jsonb
  ),
  (
    'intergenerational-10-passes',
    'football_game',
    'low',
    '{"en":"Intergenerational 10 Passes","it":"10 Passaggi Intergenerazionali","pl":"Międzypokoleniowe 10 podań","uk":"Міжпоколеннєві 10 передач"}'::jsonb,
    '{"en":"Players of different ages work together to make 10 consecutive passes. 1. Divide players into teams with a mix of ages.\n2. Start with a pass from one player to another.\n3. Each team tries to make 10 consecutive passes without the ball being intercepted.\n4. If the ball is intercepted, the count starts over.","pl":"Zawodnicy w różnym wieku współpracują, aby wykonać 10 kolejnych podań. 1. Podziel zawodników na zespoły z mieszanym wiekiem.\n2. Rozpocznij od podania od jednego zawodnika do drugiego.\n3. Każdy zespół próbuje wykonać 10 kolejnych podań bez przechwycenia piłki.\n4. Jeśli piłka zostanie przechwycona, liczenie zaczyna się od nowa.","it":"Giocatori di diverse età lavorano insieme per fare 10 passaggi consecutivi. 1. Dividere i giocatori in squadre con un mix di età.\n2. Iniziare con un passaggio da un giocatore all''altro.\n3. Ogni squadra cerca di fare 10 passaggi consecutivi senza che la palla venga intercettata.\n4. Se la palla viene intercettata, il conteggio ricomincia da capo.","uk":"Гравці різних вікових груп працюють разом, щоб зробити 10 послідовних передач. 1. Розділіть гравців на команди з різним віком.\n2. Почніть з передачі від одного гравця до іншого.\n3. Кожна команда намагається зробити 10 послідовних передач без перехвату м''яча.\n4. Якщо м''яч буде перехоплений, рахунок починається спочатку."}'::jsonb,
    'https://www.youtube.com/watch?v=jpDDqQg9aXc',
    '{"ball"}'::text[],
    10,
    8,
    99,
    '{"en":"This exercise promotes teamwork and communication among players of different ages. Famous players like Andrea Pirlo and Luka Modrić are known for their exceptional passing skills.","it":"Questo esercizio promuove il lavoro di squadra e la comunicazione tra giocatori di diverse età. Giocatori famosi come Andrea Pirlo e Luka Modrić sono noti per le loro eccezionali abilità di passaggio.","pl":"Ten ćwiczenie promuje pracę zespołową i komunikację między zawodnikami w różnym wieku. Znani zawodnicy, tacy jak Andrea Pirlo i Luka Modrić, są znani ze swoich wyjątkowych umiejętności podawania.","uk":"Це вправа сприяє команді роботі та спілкуванню між гравцями різних вікових груп. Відомі гравці, такі як Андреа Пірло та Лука Модрич, відомі своїми винятковими навичками передач."}'::jsonb,
    '{"en":["Communication","Teamwork","Passing accuracy"],"it":["Comunicazione","Lavoro di squadra","Precisione di passaggio"],"pl":["Komunikacja","Praca zespołowa","Dokładność podania"],"uk":["Комунікація","Командна робота","Точність передач"]}'::jsonb,
    '{"en":"Encourage players to move into open spaces to create passing opportunities.","it":"Incoraggia i giocatori a muoversi in spazi aperti per creare opportunità di passaggio.","pl":"Zachęcaj zawodników do poruszania się w otwartych przestrzeniach, aby stworzyć możliwości podania.","uk":"Заохочуйте гравців переміщатися у відкриті простори, щоб створити можливості для передач."}'::jsonb
  ),
  (
    'goalkeeper-challenge-weak-foot',
    'football_game',
    'low',
    '{"en":"Goalkeeper Weak Foot Challenge","it":"Sfida portiere piede debole","pl":"Wyzwanie dla bramkarza - słaba noga","uk":"Виклик для воротаря - слабка нога"}'::jsonb,
    '{"en":"This exercise tests a goalkeeper''s ability to handle shots with their weaker foot. 1. Set up a series of balls in front of the goal.\n2. The goalkeeper starts at the goal line.\n3. A coach or player takes shots from different angles using their weaker foot.\n4. The goalkeeper must react and save the shots.","pl":"Ten ćwiczenie sprawdza umiejętność bramkarza do obsługi strzałów słabszą nogą. 1. Ustaw szereg piłek przed bramką.\n2. Bramkarz zaczyna na linii bramkowej.\n3. Trener lub zawodnik oddaje strzały z różnych kątów używając słabszej nogi.\n4. Bramkarz musi reagować i bronić strzałów.","it":"Questo esercizio testa la capacità di un portiere di gestire tiri con il piede più debole. 1. Disponi una serie di palloni davanti alla porta.\n2. Il portiere inizia sulla linea di porta.\n3. Un allenatore o un giocatore tira da diverse angolazioni usando il piede più debole.\n4. Il portiere deve reagire e parare i tiri.","uk":"Це вправу перевіряє здатність воротаря справлятися з ударами слабкою ногою. 1. Встановіть серію м''ячів перед воротами.\n2. Воротар починає на лінії воріт.\n3. Тренер або гравець завдає удари з різних кутів, використовуючи слабку ногу.\n4. Воротар повинен реагувати та відбивати удари."}'::jsonb,
    'https://www.youtube.com/watch?v=pLI4qIRT-G8',
    '{"ball"}'::text[],
    10,
    12,
    99,
    '{"en":"This exercise matters because it helps goalkeepers improve their reaction time and ability to handle shots from different angles. Famous goalkeepers like David Seaman and Manuel Neuer have emphasized the importance of being able to handle shots with their weaker foot.","it":"Questo esercizio è importante perché aiuta i portieri a migliorare il loro tempo di reazione e la capacità di gestire tiri da diverse angolazioni. Famosi portieri come David Seaman e Manuel Neuer hanno sottolineato l''importanza di essere in grado di gestire tiri con il piede più debole.","pl":"To ćwiczenie jest ważne, ponieważ pomaga bramkarzom poprawić czas reakcji i umiejętność obsługi strzałów z różnych kątów. Znani bramkarze tacy jak David Seaman i Manuel Neuer podkreślali znaczenie umiejętności obrony strzałów słabszą nogą.","uk":"Це вправу важливе, тому що воно допомагає воротарям поліпшити час реакції та здатність справлятися з ударами з різних кутів. Відомі воротарі, такі як Девід Сімен та Мануель Нойер, підкреслювали важливість вміння відбивати удари слабкою ногою."}'::jsonb,
    '{"en":["Reaction time","Footwork","Hand-eye coordination"],"it":["Tempo di reazione","Movimenti dei piedi","Coordinazione occhio-mano"],"pl":["Czas reakcji","Poruszanie się","Koordynacja ręka-oko"],"uk":["Час реакції","Рухи ніг","Координація око-рука"]}'::jsonb,
    '{"en":"Encourage the goalkeeper to stay focused and anticipate the direction of the shot.","it":"Incoraggia il portiere a rimanere concentrato e ad anticipare la direzione del tiro.","pl":"Zachęcaj bramkarza do pozostania skoncentrowanym i przewidywania kierunku strzału.","uk":"Заохочуйте воротаря залишатися зосередженим та передбачати напрямок удару."}'::jsonb
  ),
  (
    'freestyle-juggling-comp',
    'football_game',
    'mid',
    '{"en":"Freestyle Juggling Comp","it":"Competizione di palleggio","pl":"Zawody w żonglowaniu","uk":"Змагання з жонглювання"}'::jsonb,
    '{"en":"Improve your ball control with a fun competition to see who can juggle the longest. 1. Divide players into pairs or small groups. 2. Each player starts juggling with their feet or thighs. 3. If a player drops the ball, their opponent gets a point. 4. The player with the most points after a set time wins.","pl":"Popraw kontrolę nad piłką dzięki zabawnej rywalizacji, aby zobaczyć, kto może żonglować najdłużej. 1. Podziel zawodników na pary lub małe grupy. 2. Każdy zawodnik zaczyna żonglować piłką nogami lub udami. 3. Jeśli zawodnik upuści piłkę, jego przeciwnik zdobywa punkt. 4. Zawodnik z największą liczbą punktów po ustalonym czasie wygrywa.","it":"Migliora il tuo controllo della palla con una divertente competizione per vedere chi può palleggiare più a lungo. 1. Dividere i giocatori in coppie o piccoli gruppi. 2. Ogni giocatore inizia a palleggiare con i piedi o le cosce. 3. Se un giocatore lascia cadere la palla, il suo avversario ottiene un punto. 4. Il giocatore con più punti dopo un tempo prestabilito vince.","uk":"Поліпшуйте свій контроль над м''ячем за допомогою цікавого змагання, щоб побачити, хто може жонглювати найдовше. 1. Розділіть гравців на пари або маленькі групи. 2. Кожен гравець починає жонглювати м''ячем ногами або стегнами. 3. Якщо гравець впустив м''яч, його суперник отримує очко. 4. Гравець з найбільшою кількістю очок після встановленого часу виграє."}'::jsonb,
    'https://www.youtube.com/watch?v=tcfRdkrqYzs',
    '{"ball"}'::text[],
    8,
    12,
    99,
    '{"en":"This exercise improves ball control, coordination and mental focus. Players like Cristiano Ronaldo and Lionel Messi are famous for their juggling skills.","it":"Questo esercizio migliora il controllo della palla, la coordinazione e la concentrazione mentale. Giocatori come Cristiano Ronaldo e Lionel Messi sono famosi per le loro abilità di palleggio.","pl":"Ten ćwiczenie poprawia kontrolę nad piłką, koordynację i koncentrację umysłową. Zawodnicy tacy jak Cristiano Ronaldo i Lionel Messi są znani ze swoich umiejętności żonglowania.","uk":"Це вправу поліпшує контроль над м''ячем, координацію та психічну концентрацію. Гравці такі як Крістіано Роналду і Ліонель Мессі відомі своїми навичками жонглювання."}'::jsonb,
    '{"en":["Ball control","Coordination","Mental focus"],"it":["Controllo della palla","Coordinazione","Concentrazione mentale"],"pl":["Kontrola nad piłką","Koordynacja","Koncentracja umysłowa"],"uk":["Контроль над м''ячем","Координація","Психічна концентрація"]}'::jsonb,
    '{"en":"Encourage players to try different juggling techniques, such as using different parts of the body or alternating feet.","it":"Incoraggia i giocatori a provare diverse tecniche di palleggio, come usare diverse parti del corpo o alternare i piedi.","pl":"Zachęcaj zawodników do wypróbowania różnych technik żonglowania, takich jak używanie różnych części ciała lub naprzemienne nogi.","uk":"Заохочуйте гравців спробувати різні техніки жонглювання, такі як використання різних частин тіла або почергове використання ніг."}'::jsonb
  ),
  (
    'shooting-king-of-the-hill',
    'football_game',
    'mid',
    '{"en":"King of the Hill Shooting","it":"Tiro Re della Collina","pl":"Król Wzgórza - Strzały","uk":"Король Пагорка - Удари"}'::jsonb,
    '{"en":"Players compete to score the most goals from a series of shots, with the goal of being crowned ''King of the Hill''. 1. Divide players into small groups of 3-4. 2. Set up a series of small goals or cones to create a ''hill'' area. 3. Each player takes turns shooting from a designated spot, trying to score as many goals as possible. 4. The player with the most goals after a set time limit is crowned ''King of the Hill''.","pl":"Zawodnicy rywalizują ze sobą, aby strzelić jak najwięcej goli z serii strzałów, a celem jest koronacja na Króla Wzgórza. 1. Podziel zawodników na małe grupy 3-4 osobowe. 2. Ustaw szereg małych bramek lub stożków, aby utworzyć obszar ''wzgórza''. 3. Każdy zawodnik po kolei strzela z wyznaczonego miejsca, próbując zdobyć jak najwięcej goli. 4. Zawodnik, który strzeli najwięcej goli w określonym limicie czasowym, zostaje koronowany na Króla Wzgórza.","it":"I giocatori competono per segnare il maggior numero di gol da una serie di tiri, con l''obiettivo di essere incoronato ''Re della Collina''. 1. Dividere i giocatori in piccoli gruppi di 3-4. 2. Allestire una serie di piccoli obiettivi o coni per creare un''area ''collina''. 3. Ogni giocatore a turno spara da un punto designato, cercando di segnare quanti più gol possibile. 4. Il giocatore con il maggior numero di gol dopo un limite di tempo prestabilito viene incoronato ''Re della Collina''.","uk":"Гравці змагаються за те, щоб забити найбільшу кількість голів із серії ударів, з метою бути увінчаним Королем Пагорка. 1. Розділити гравців на малі групи по 3-4 особи. 2. Встановити ряд малих воріт або конусів, щоб створити зону ''пагорка''. 3. Кожен гравець по черзі б''є з визначеного місця, намагаючись забити якомога більше голів. 4. Гравець, який забив найбільшу кількість голів у встановлений ліміт часу, стає Королем Пагорка."}'::jsonb,
    'https://www.youtube.com/watch?v=hLLmKEogJ_Q',
    '{"ball"}'::text[],
    12,
    12,
    99,
    '{"en":"This exercise helps improve shooting technique and accuracy, as well as mental toughness and competitiveness. Famous players like Cristiano Ronaldo and Lionel Messi are known for their exceptional shooting skills.","it":"Questo esercizio aiuta a migliorare la tecnica e la precisione di tiro, oltre alla resistenza mentale e alla competitività. Giocatori famosi come Cristiano Ronaldo e Lionel Messi sono noti per le loro eccezionali abilità di tiro.","pl":"Ten ćwiczenie pomaga poprawić technikę i dokładność strzału, a także wytrzymałość psychiczną i konkurencyjność. Znani zawodnicy tacy jak Cristiano Ronaldo i Lionel Messi są znani z ich wyjątkowych umiejętności strzeleckich.","uk":"Це вправ допомагає покращити техніку та точність удару, а також психічну витривалість і конкурентність. Відомі гравці, такі як Крістіано Роналду і Ліонель Мессі, відомі своїми винятковими навичками удару."}'::jsonb,
    '{"en":["Shooting technique","Accuracy","Mental toughness"],"it":["Tecnica di tiro","Precisione","Resistenza mentale"],"pl":["Technika strzału","Dokładność","Wytrzymałość psychiczna"],"uk":["Техніка удару","Точність","Психічна витривалість"]}'::jsonb,
    '{"en":"Encourage players to visualize the ball going into the goal before taking their shot.","it":"Incoraggia i giocatori a visualizzare la palla che entra in porta prima di effettuare il tiro.","pl":"Zachęcać zawodników do wizualizacji piłki wpadającej do bramki przed oddaniem strzału.","uk":"Заохочуйте гравців візуалізувати м''яч, що потрапляє у ворота, перед тим, як зробити удар."}'::jsonb
  )
;
